import type { BibleBook } from '../bibleData';

// Auto-generated from public-domain sources: World English Bible (WEB, EN)
// and João Ferreira de Almeida (Almeida, PT), via seven1m/open-bibles (USFX).
// Do not edit by hand — regenerate with scripts/generate-bible.

const book: BibleBook = {
  id: '1corinthians',
  name: '1 Coríntios',
  englishName: '1 Corinthians',
  testament: 'new',
  chapters: {
    1: [
      { v: 1, en: 'Paul, called to be an apostle of Jesus Christ through the will of God, and our brother Sosthenes,', pt: 'Paulo, chamado para ser apóstolo de Jesus Cristo pela vontade de Deus, e o irmão Sóstenes,' },
      { v: 2, en: 'to the assembly of God which is at Corinth; those who are sanctified in Christ Jesus, called to be saints, with all who call on the name of our Lord Jesus Christ in every place, both theirs and ours:', pt: 'à igreja de Deus que está em Corinto, aos santificados em Cristo Jesus, chamados para serem santos, com todos os que em todo lugar invocam o nome de nosso Senhor Jesus Cristo, Senhor deles e nosso:' },
      { v: 3, en: 'Grace to you and peace from God our Father and the Lord Jesus Christ.', pt: 'Graça seja convosco, e paz, da parte de Deus nosso Pai, e do Senhor Jesus Cristo.' },
      { v: 4, en: 'I always thank my God concerning you, for the grace of God which was given you in Christ Jesus;', pt: 'Sempre dou graças a Deus por vós, pela graça de Deus que vos foi dada em Cristo Jesus;' },
      { v: 5, en: 'that in everything you were enriched in him, in all speech and all knowledge;', pt: 'porque em tudo fostes enriquecidos nele, em toda palavra e em todo o conhecimento,' },
      { v: 6, en: 'even as the testimony of Christ was confirmed in you:', pt: 'assim como o testemunho de Cristo foi confirmado entre vós;' },
      { v: 7, en: 'so that you come behind in no gift; waiting for the revelation of our Lord Jesus Christ;', pt: 'de maneira que nenhum dom vos falta, enquanto aguardais a manifestação de nosso Senhor Jesus Cristo,' },
      { v: 8, en: 'who will also confirm you until the end, blameless in the day of our Lord Jesus Christ.', pt: 'o qual também vos confirmará até o fim, para serdes irrepreensíveis no dia de nosso Senhor Jesus Cristo.' },
      { v: 9, en: 'God is faithful, through whom you were called into the fellowship of his Son, Jesus Christ, our Lord.', pt: 'Fiel é Deus, pelo qual fostes chamados para a comunhão de seu Filho Jesus Cristo nosso Senhor.' },
      { v: 10, en: 'Now I beg you, brothers, through the name of our Lord, Jesus Christ, that you all speak the same thing, and that there be no divisions among you, but that you be perfected together in the same mind and in the same judgment.', pt: 'Rogo-vos, irmãos, em nome de nosso Senhor Jesus Cristo, que sejais concordes no falar, e que não haja dissensões entre vós; antes sejais unidos no mesmo pensamento e no mesmo parecer.' },
      { v: 11, en: 'For it has been reported to me concerning you, my brothers, by those who are from Chloe’s household, that there are contentions among you.', pt: 'Pois a respeito de vós, irmãos meus, fui informado pelos da família de Cloé que há contendas entre vós.' },
      { v: 12, en: 'Now I mean this, that each one of you says, “I follow Paul,” “I follow Apollos,” “I follow Cephas,” and, “I follow Christ.”', pt: 'Quero dizer com isto, que cada um de vós diz: Eu sou de Paulo; ou, Eu de Apolo; ou Eu sou de Cefas; ou, Eu de Cristo.' },
      { v: 13, en: 'Is Christ divided? Was Paul crucified for you? Or were you baptized into the name of Paul?', pt: 'será que Cristo está dividido? foi Paulo crucificado por amor de vós? ou fostes vós batizados em nome de Paulo?' },
      { v: 14, en: 'I thank God that I baptized none of you, except Crispus and Gaius,', pt: 'Dou graças a Deus que a nenhum de vós batizei, senão a Crispo e a Gaio;' },
      { v: 15, en: 'so that no one should say that I had baptized you into my own name.', pt: 'para que ninguém diga que fostes batizados em meu nome.' },
      { v: 16, en: '(I also baptized the household of Stephanas; besides them, I don’t know whether I baptized any other.)', pt: 'É verdade, batizei também a família de Estéfanas, além destes, não sei se batizei algum outro.' },
      { v: 17, en: 'For Christ sent me not to baptize, but to preach the Good News—not in wisdom of words, so that the cross of Christ wouldn’t be made void.', pt: 'Porque Cristo não me enviou para batizar, mas para pregar o evangelho; não em sabedoria de palavras, para não se tornar vã a cruz de Cristo.' },
      { v: 18, en: 'For the word of the cross is foolishness to those who are dying, but to us who are saved it is the power of God.', pt: 'Porque a palavra da cruz é deveras loucura para os que perecem; mas para nós, que somos salvos, é o poder de Deus.' },
      { v: 19, en: 'For it is written, “I will destroy the wisdom of the wise, I will bring the discernment of the discerning to nothing.”', pt: 'porque está escrito: Destruirei a sabedoria dos sábios, e aniquilarei a sabedoria o entendimento dos entendidos.' },
      { v: 20, en: 'Where is the wise? Where is the scribe? Where is the lawyer of this world? Hasn’t God made foolish the wisdom of this world?', pt: 'Onde está o sábio? Onde o escriba? Onde o questionador deste século? Porventura não tornou Deus louca a sabedoria deste mundo?' },
      { v: 21, en: 'For seeing that in the wisdom of God, the world through its wisdom didn’t know God, it was God’s good pleasure through the foolishness of the preaching to save those who believe.', pt: 'Visto como na sabedoria de Deus o mundo pela sua sabedoria não conheceu a Deus, aprouve a Deus salvar pela loucura da pregação os que crêem.' },
      { v: 22, en: 'For Jews ask for signs, Greeks seek after wisdom,', pt: 'Pois, enquanto os judeus pedem sinal, e os gregos buscam sabedoria,' },
      { v: 23, en: 'but we preach Christ crucified; a stumbling block to Jews, and foolishness to Greeks,', pt: 'nós pregamos a Cristo crucificado, que é escândalo para os judeus, e loucura para os gregos,' },
      { v: 24, en: 'but to those who are called, both Jews and Greeks, Christ is the power of God and the wisdom of God.', pt: 'mas para os que são chamados, tanto judeus como gregos, Cristo, poder de Deus, e sabedoria de Deus.' },
      { v: 25, en: 'Because the foolishness of God is wiser than men, and the weakness of God is stronger than men.', pt: 'Porque a loucura de Deus é mais sábia que os homens; e a fraqueza de Deus é mais forte que os homens.' },
      { v: 26, en: 'For you see your calling, brothers, that not many are wise according to the flesh, not many mighty, and not many noble;', pt: 'Ora, vede, irmãos, a vossa vocação, que não são muitos os sábios segundo a carne, nem muitos os poderosos. nem muitos os nobres que são chamados.' },
      { v: 27, en: 'but God chose the foolish things of the world that he might put to shame those who are wise. God chose the weak things of the world, that he might put to shame the things that are strong;', pt: 'Pelo contrário, Deus escolheu as coisas loucas do mundo para confundir os sábios; e Deus escolheu as coisas fracas do mundo para confundir as fortes;' },
      { v: 28, en: 'and God chose the lowly things of the world, and the things that are despised, and the things that are not, that he might bring to nothing the things that are:', pt: 'e Deus escolheu as coisas ignóbeis do mundo, e as desprezadas, e as que não são, para reduzir a nada as que são;' },
      { v: 29, en: 'that no flesh should boast before God.', pt: 'para que nenhum mortal se glorie na presença de Deus.' },
      { v: 30, en: 'Because of him, you are in Christ Jesus, who was made to us wisdom from God, and righteousness and sanctification, and redemption:', pt: 'Mas vós sois dele, em Cristo Jesus, o qual para nós foi feito por Deus sabedoria, e justiça, e santificação, e redenção;' },
      { v: 31, en: 'that, according as it is written, “He who boasts, let him boast in the Lord.”', pt: 'para que, como está escrito: Aquele que se gloria, glorie-se no Senhor.' },
    ],
    2: [
      { v: 1, en: 'When I came to you, brothers, I didn’t come with excellence of speech or of wisdom, proclaiming to you the testimony of God.', pt: 'E eu, irmãos, quando fui ter convosco, anunciando-vos o testemunho de Deus, não fui com sublimidade de palavras ou de sabedoria.' },
      { v: 2, en: 'For I determined not to know anything among you, except Jesus Christ, and him crucified.', pt: 'Porque nada me propus saber entre vós, senão a Jesus Cristo, e este crucificado.' },
      { v: 3, en: 'I was with you in weakness, in fear, and in much trembling.', pt: 'E eu estive convosco em fraqueza, e em temor, e em grande tremor.' },
      { v: 4, en: 'My speech and my preaching were not in persuasive words of human wisdom, but in demonstration of the Spirit and of power,', pt: 'A minha linguagem e a minha pregação não consistiram em palavras persuasivas de sabedoria, mas em demonstração do Espírito de poder;' },
      { v: 5, en: 'that your faith wouldn’t stand in the wisdom of men, but in the power of God.', pt: 'para que a vossa fé não se apoiasse na sabedoria dos homens, mas no poder de Deus.' },
      { v: 6, en: 'We speak wisdom, however, among those who are full grown; yet a wisdom not of this world, nor of the rulers of this world, who are coming to nothing.', pt: 'Na verdade, entre os perfeitos falamos sabedoria, não porém a sabedoria deste mundo, nem dos príncipes deste mundo, que estão sendo reduzidos a nada;' },
      { v: 7, en: 'But we speak God’s wisdom in a mystery, the wisdom that has been hidden, which God foreordained before the worlds for our glory,', pt: 'mas falamos a sabedoria de Deus em mistério, que esteve oculta, a qual Deus preordenou antes dos séculos para nossa glória;' },
      { v: 8, en: 'which none of the rulers of this world has known. For had they known it, they wouldn’t have crucified the Lord of glory.', pt: 'a qual nenhum dos príncipes deste mundo compreendeu; porque se a tivessem compreendido, não teriam crucificado o Senhor da glória.' },
      { v: 9, en: 'But as it is written, “Things which an eye didn’t see, and an ear didn’t hear, which didn’t enter into the heart of man, these God has prepared for those who love him.”', pt: 'Mas, como está escrito: As coisas que olhos não viram, nem ouvidos ouviram, nem penetraram o coração do homem, são as que Deus preparou para os que o amam.' },
      { v: 10, en: 'But to us, God revealed them through the Spirit. For the Spirit searches all things, yes, the deep things of God.', pt: 'Porque Deus no-las revelou pelo seu Espírito; pois o Espírito esquadrinha todas as coisas, mesmos as profundezas de Deus.' },
      { v: 11, en: 'For who among men knows the things of a man, except the spirit of the man, which is in him? Even so, no one knows the things of God, except God’s Spirit.', pt: 'Pois, qual dos homens entende as coisas do homem, senão o espírito do homem que nele está? assim também as coisas de Deus, ninguém as compreendeu, senão o Espírito de Deus.' },
      { v: 12, en: 'But we received, not the spirit of the world, but the Spirit which is from God, that we might know the things that were freely given to us by God.', pt: 'Ora, nós não temos recebido o espírito do mundo, mas sim o Espírito que provém de Deus, a fim de compreendermos as coisas que nos foram dadas gratuitamente por Deus;' },
      { v: 13, en: 'Which things also we speak, not in words which man’s wisdom teaches, but which the Holy Spirit teaches, comparing spiritual things with spiritual things.', pt: 'as quais também falamos, não com palavras ensinadas pela sabedoria humana, mas com palavras ensinadas pelo Espírito Santo, comparando coisas espirituais com espirituais.' },
      { v: 14, en: 'Now the natural man doesn’t receive the things of God’s Spirit, for they are foolishness to him, and he can’t know them, because they are spiritually discerned.', pt: 'Ora, o homem natural não aceita as coisas do Espírito de Deus, porque para ele são loucura; e não pode entendê-las, porque elas se discernem espiritualmente.' },
      { v: 15, en: 'But he who is spiritual discerns all things, and he himself is judged by no one.', pt: 'Mas o que é espiritual discerne bem tudo, enquanto ele por ninguém é discernido.' },
      { v: 16, en: '“For who has known the mind of the Lord, that he should instruct him?” But we have Christ’s mind.', pt: 'Pois, quem jamais conheceu a mente do Senhor, para que possa instruí-lo? Mas nós temos a mente de Cristo.' },
    ],
    3: [
      { v: 1, en: 'Brothers, I couldn’t speak to you as to spiritual, but as to fleshly, as to babies in Christ.', pt: 'E eu, irmãos não vos pude falar como a espírituais, mas como a carnais, como a criancinhas em Cristo.' },
      { v: 2, en: 'I fed you with milk, not with meat; for you weren’t yet ready. Indeed, not even now are you ready,', pt: 'Leite vos dei por alimento, e não comida sólida, porque não a podíeis suportar; nem ainda agora podeis;' },
      { v: 3, en: 'for you are still fleshly. For insofar as there is jealousy, strife, and factions among you, aren’t you fleshly, and don’t you walk in the ways of men?', pt: 'porquanto ainda sois carnais; pois, havendo entre vós inveja e contendas, não sois porventura carnais, e não estais andando segundo os homens?' },
      { v: 4, en: 'For when one says, “I follow Paul,” and another, “I follow Apollos,” aren’t you fleshly?', pt: 'Porque, dizendo um: Eu sou de Paulo; e outro: Eu de Apolo; não sois apenas homens?' },
      { v: 5, en: 'Who then is Apollos, and who is Paul, but servants through whom you believed; and each as the Lord gave to him?', pt: 'Pois, que é Apolo, e que é Paulo, senão ministros pelos quais crestes, e isso conforme o que o Senhor concedeu a cada um?' },
      { v: 6, en: 'I planted. Apollos watered. But God gave the increase.', pt: 'Eu plantei; Apolo regou; mas Deus deu o crescimento.' },
      { v: 7, en: 'So then neither he who plants is anything, nor he who waters, but God who gives the increase.', pt: 'De modo que, nem o que planta é alguma coisa, nem o que rega, mas Deus, que dá o crescimento.' },
      { v: 8, en: 'Now he who plants and he who waters are the same, but each will receive his own reward according to his own labor.', pt: 'Ora, uma só coisa é o que planta e o que rega; e cada um receberá o seu galardão segundo o seu trabalho.' },
      { v: 9, en: 'For we are God’s fellow workers. You are God’s farming, God’s building.', pt: 'Porque nós somos cooperadores de Deus; vós sois lavoura de Deus e edifício de Deus.' },
      { v: 10, en: 'According to the grace of God which was given to me, as a wise master builder I laid a foundation, and another builds on it. But let each man be careful how he builds on it.', pt: 'Segundo a graça de Deus que me foi dada, lancei eu como sábio construtor, o fundamento, e outro edifica sobre ele; mas veja cada um como edifica sobre ele.' },
      { v: 11, en: 'For no one can lay any other foundation than that which has been laid, which is Jesus Christ.', pt: 'Porque ninguém pode lançar outro fundamento, além do que já está posto, o qual é Jesus Cristo.' },
      { v: 12, en: 'But if anyone builds on the foundation with gold, silver, costly stones, wood, hay, or stubble;', pt: 'E, se alguém sobre este fundamento levanta um edifício de ouro, prata, pedras preciosas, madeira, feno, palha,' },
      { v: 13, en: 'each man’s work will be revealed. For the Day will declare it, because it is revealed in fire; and the fire itself will test what sort of work each man’s work is.', pt: 'a obra de cada um se manifestará; pois aquele dia a demonstrará, porque será reveldada no fogo, e o fogo provará qual seja a obra de cada um.' },
      { v: 14, en: 'If any man’s work remains which he built on it, he will receive a reward.', pt: 'Se permanecer a obra que alguém sobre ele edificou, esse receberá galardão.' },
      { v: 15, en: 'If any man’s work is burned, he will suffer loss, but he himself will be saved, but as through fire.', pt: 'Se a obra de alguém se queimar, sofrerá ele prejuízo; mas o tal será salvo todavia como que pelo fogo.' },
      { v: 16, en: 'Don’t you know that you are a temple of God, and that God’s Spirit lives in you?', pt: 'Não sabeis vós que sois santuário de Deus, e que o Espírito de Deus habita em vós?' },
      { v: 17, en: 'If anyone destroys God’s temple, God will destroy him; for God’s temple is holy, which you are.', pt: 'Se alguém destruir o santuário de Deus, Deus o destruirá; porque sagrado é o santuário de Deus, que sois vós.' },
      { v: 18, en: 'Let no one deceive himself. If anyone thinks that he is wise among you in this world, let him become a fool, that he may become wise.', pt: 'Ninguém se engane a si mesmo; se alguém dentre vós se tem por sábio neste mundo, faça-se louco para se tornar sábio.' },
      { v: 19, en: 'For the wisdom of this world is foolishness with God. For it is written, “He has taken the wise in their craftiness.”', pt: 'Porque a sabedoria deste mundo é loucura diante de Deus; pois está escrito: Ele apanha os sábios na sua própria astúcia;' },
      { v: 20, en: 'And again, “The Lord knows the reasoning of the wise, that it is worthless.”', pt: 'e outra vez: O Senhor conhece as cogitações dos sábios, que são vãs.' },
      { v: 21, en: 'Therefore let no one boast in men. For all things are yours,', pt: 'Portanto ninguém se glorie nos homens; porque tudo é vosso;' },
      { v: 22, en: 'whether Paul, or Apollos, or Cephas, or the world, or life, or death, or things present, or things to come. All are yours,', pt: 'seja Paulo, ou Apolo, ou Cefas; seja o mundo, ou a vida, ou a morte; sejam as coisas presentes, ou as vindouras, tudo é vosso,' },
      { v: 23, en: 'and you are Christ’s, and Christ is God’s.', pt: 'e vós de Cristo, e Cristo de Deus.' },
    ],
    4: [
      { v: 1, en: 'So let a man think of us as Christ’s servants, and stewards of God’s mysteries.', pt: 'Que os homens nos considerem, pois, como ministros de Cristo, e despenseiros dos mistérios de Deus.' },
      { v: 2, en: 'Here, moreover, it is required of stewards, that they be found faithful.', pt: 'Ora, além disso, o que se requer nos despenseiros é que cada um seja encontrado fiel.' },
      { v: 3, en: 'But with me it is a very small thing that I should be judged by you, or by man’s judgment. Yes, I don’t judge my own self.', pt: 'Todavia, a mim mui pouco se me dá de ser julgado por vós, ou por qualquer tribunal humano; nem eu tampouco a mim mesmo me julgo.' },
      { v: 4, en: 'For I know nothing against myself. Yet I am not justified by this, but he who judges me is the Lord.', pt: 'Porque, embora em nada me sinta culpado, nem por isso sou justificado; pois quem me julga é o Senhor.' },
      { v: 5, en: 'Therefore judge nothing before the time, until the Lord comes, who will both bring to light the hidden things of darkness, and reveal the counsels of the hearts. Then each man will get his praise from God.', pt: 'Portanto nada julgueis antes do tempo, até que venha o Senhor, o qual não só trará à luz as coisas ocultas das trevas, mas também manifestará os desígnios dos corações; e então cada um receberá de Deus o seu louvor.' },
      { v: 6, en: 'Now these things, brothers, I have in a figure transferred to myself and Apollos for your sakes, that in us you might learn not to think beyond the things which are written, that none of you be puffed up against one another.', pt: 'Ora, irmãos, estas coisas eu as apliquei figuradamente a mim e a Apolo, por amor de vós; para que em nós aprendais a não ir além do que está escrito, de modo que nenhum de vós se ensoberbeça a favor de um contra outro.' },
      { v: 7, en: 'For who makes you different? And what do you have that you didn’t receive? But if you did receive it, why do you boast as if you had not received it?', pt: 'Pois, quem te diferença? E que tens tu que não tenhas recebido? E, se o recebeste, por que te glorias, como se não o houveras recebido?' },
      { v: 8, en: 'You are already filled. You have already become rich. You have come to reign without us. Yes, and I wish that you did reign, that we also might reign with you.', pt: 'Já estais fartos! já estais ricos! sem nós já chegastes a reinar! e oxalá reinásseis de fato, para que também nós reinássemos convosco!' },
      { v: 9, en: 'For, I think that God has displayed us, the apostles, last of all, like men sentenced to death. For we are made a spectacle to the world, both to angels and men.', pt: 'Porque tenho para mim, que Deus a nós, apóstolos, nos pôs por últimos, como condenados à morte; pois somos feitos espetáculo ao mundo, tanto a anjos como a homens.' },
      { v: 10, en: 'We are fools for Christ’s sake, but you are wise in Christ. We are weak, but you are strong. You have honor, but we have dishonor.', pt: 'Nós somos loucos por amor de Cristo, e vós sábios em Cristo; nós fracos, e vós fortes; vós ilustres, e nós desprezíveis.' },
      { v: 11, en: 'Even to this present hour we hunger, thirst, are naked, are beaten, and have no certain dwelling place.', pt: 'Até a presente hora padecemos fome, e sede; estamos nus, e recebemos bofetadas, e não temos pousada certa,' },
      { v: 12, en: 'We toil, working with our own hands. When people curse us, we bless. Being persecuted, we endure.', pt: 'e nos afadigamos, trabalhando com nossas próprias mãos; somos injuriados, e bendizemos; somos perseguidos, e o suportamos;' },
      { v: 13, en: 'Being defamed, we entreat. We are made as the filth of the world, the dirt wiped off by all, even until now.', pt: 'somos difamados, e exortamos; até o presente somos considerados como o refugo do mundo, e como a escória de tudo.' },
      { v: 14, en: 'I don’t write these things to shame you, but to admonish you as my beloved children.', pt: 'Não escrevo estas coisas para vos envergonhar, mas para vos admoestar, como a filhos meus amados.' },
      { v: 15, en: 'For though you have ten thousand tutors in Christ, you don’t have many fathers. For in Christ Jesus, I became your father through the Good News.', pt: 'Porque ainda que tenhais dez mil aios em Cristo, não tendes contudo muitos pais; pois eu pelo evangelho vos gerei em Cristo Jesus.' },
      { v: 16, en: 'I beg you therefore, be imitators of me.', pt: 'Rogo-vos, portanto, que sejais meus imitadores.' },
      { v: 17, en: 'Because of this I have sent Timothy to you, who is my beloved and faithful child in the Lord, who will remind you of my ways which are in Christ, even as I teach everywhere in every assembly.', pt: 'Por isso mesmo vos enviei Timóteo, que é meu filho amado, e fiel no Senhor; o qual vos lembrará os meus caminhos em Cristo, como por toda parte eu ensino em cada igreja.' },
      { v: 18, en: 'Now some are puffed up, as though I were not coming to you.', pt: 'Mas alguns andam inchados, como se eu não houvesse de ir ter convosco.' },
      { v: 19, en: 'But I will come to you shortly, if the Lord is willing. And I will know, not the word of those who are puffed up, but the power.', pt: 'Em breve, porém, irei ter convosco, se o Senhor quiser, e então conhecerei, não as palavras dos que andam inchados, mas o poder.' },
      { v: 20, en: 'For God’s Kingdom is not in word, but in power.', pt: 'Porque o reino de Deus não consiste em palavras, mas em poder.' },
      { v: 21, en: 'What do you want? Shall I come to you with a rod, or in love and a spirit of gentleness?', pt: 'Que quereis? Irei a vós com vara, ou com amor e espírito de mansidão?' },
    ],
    5: [
      { v: 1, en: 'It is actually reported that there is sexual immorality among you, and such sexual immorality as is not even named among the Gentiles, that one has his father’s wife.', pt: 'para que a recebais no Senhor, de um modo digno dos santos, imoralidade que nem mesmo entre os gentios se vê, a ponto de haver quem vive com a mulher de seu pai.' },
      { v: 2, en: 'You are puffed up, and didn’t rather mourn, that he who had done this deed might be removed from among you.', pt: 'E vós estais inchados? e nem ao menos pranteastes para que fosse tirado do vosso meio quem praticou esse mal?' },
      { v: 3, en: 'For I most certainly, as being absent in body but present in spirit, have already, as though I were present, judged him who has done this thing.', pt: 'Eu, na verdade, ainda que ausente no corpo, mas presente no espírito, já julguei, como se estivesse presente, aquele que cometeu este ultraje.' },
      { v: 4, en: 'In the name of our Lord Jesus Christ, you being gathered together, and my spirit, with the power of our Lord Jesus Christ,', pt: 'Em nome de nosso Senhor Jesus, congregados vós e o meu espírito, pelo poder de nosso Senhor Jesus,' },
      { v: 5, en: 'are to deliver such a one to Satan for the destruction of the flesh, that the spirit may be saved in the day of the Lord Jesus.', pt: 'seja entregue a Satanás para destruição da carne, para que o espírito seja salvo no dia do Senhor Jesus.' },
      { v: 6, en: 'Your boasting is not good. Don’t you know that a little yeast leavens the whole lump?', pt: 'Não é boa a vossa jactância. Não sabeis que um pouco de fermento leveda a massa toda?' },
      { v: 7, en: 'Purge out the old yeast, that you may be a new lump, even as you are unleavened. For indeed Christ, our Passover, has been sacrificed in our place.', pt: 'Expurgai o fermento velho, para que sejais massa nova, assim como sois sem fermento. Porque Cristo, nossa páscoa, já foi sacrificado.' },
      { v: 8, en: 'Therefore let us keep the feast, not with old yeast, neither with the yeast of malice and wickedness, but with the unleavened bread of sincerity and truth.', pt: 'Pelo que celebremos a festa, não com o fermento velho, nem com o fermento da malícia e da corrupção, mas com os ázimos da sinceridade e da verdade.' },
      { v: 9, en: 'I wrote to you in my letter to have no company with sexual sinners;', pt: 'Já por carta vos escrevi que não vos comunicásseis com os que se prostituem;' },
      { v: 10, en: 'yet not at all meaning with the sexual sinners of this world, or with the covetous and extortionists, or with idolaters; for then you would have to leave the world.', pt: 'com isso não me referia à comunicação em geral com os devassos deste mundo, ou com os avarentos, ou com os roubadores, ou com os idólatras; porque então vos seria necessário sair do mundo.' },
      { v: 11, en: 'But as it is, I wrote to you not to associate with anyone who is called a brother who is a sexual sinner, or covetous, or an idolater, or a slanderer, or a drunkard, or an extortionist. Don’t even eat with such a person.', pt: 'Mas agora vos escrevo que não vos comuniqueis com aquele que, dizendo-se irmão, for devasso, ou avarento, ou idólatra, ou maldizente, ou beberrão, ou roubador; com esse tal nem sequer comais.' },
      { v: 12, en: 'For what do I have to do with also judging those who are outside? Don’t you judge those who are within?', pt: 'Pois, que me importa julgar os que estão de fora? Não julgais vós os que estão de dentro?' },
      { v: 13, en: 'But those who are outside, God judges. “Put away the wicked man from among yourselves.”', pt: 'Mas Deus julga os que estão de fora. Tirai esse iníquo do meio de vós.' },
    ],
    6: [
      { v: 1, en: 'Dare any of you, having a matter against his neighbor, go to law before the unrighteous, and not before the saints?', pt: 'Ousa algum de vós, tendo uma queixa contra outro, ir a juízo perante os injustos, e não perante os santos?' },
      { v: 2, en: 'Don’t you know that the saints will judge the world? And if the world is judged by you, are you unworthy to judge the smallest matters?', pt: 'Ou não sabeis vós que os santos hão de julgar o mundo? Ora, se o mundo há de ser julgado por vós, sois porventura indignos de julgar as coisas mínimas?' },
      { v: 3, en: 'Don’t you know that we will judge angels? How much more, things that pertain to this life?', pt: 'Não sabeis vós que havemos de julgar os anjos? Quanto mais as coisas pertencentes a esta vida?' },
      { v: 4, en: 'If then, you have to judge things pertaining to this life, do you set them to judge who are of no account in the assembly?', pt: 'Então, se tiverdes negócios em juízo, pertencentes a esta vida, constituís como juízes deles os que são de menos estima na igreja?' },
      { v: 5, en: 'I say this to move you to shame. Isn’t there even one wise man among you who would be able to decide between his brothers?', pt: 'Para vos envergonhar o digo. Será que não há entre vós sequer um sábio, que possa julgar entre seus irmãos?' },
      { v: 6, en: 'But brother goes to law with brother, and that before unbelievers!', pt: 'Mas vai um irmão a juízo contra outro irmão, e isto perante incrédulos?' },
      { v: 7, en: 'Therefore it is already altogether a defect in you, that you have lawsuits one with another. Why not rather be wronged? Why not rather be defrauded?', pt: 'Na verdade já é uma completa derrota para vós o terdes demandadas uns contra os outros. Por que não sofreis antes a injustiça? Por que não sofreis antes a fraude?' },
      { v: 8, en: 'No, but you yourselves do wrong, and defraud, and that against your brothers.', pt: 'Mas vós mesmos é que fazeis injustiça e defraudais; e isto a irmãos.' },
      { v: 9, en: 'Or don’t you know that the unrighteous will not inherit God’s Kingdom? Don’t be deceived. Neither the sexually immoral, nor idolaters, nor adulterers, nor male prostitutes, nor homosexuals,', pt: 'Não sabeis que os injustos não herdarão o reino de Deus? Não vos enganeis: nem os devassos, nem os idólatras, nem os adúlteros, nem os efeminados, nem os sodomitas,' },
      { v: 10, en: 'nor thieves, nor covetous, nor drunkards, nor slanderers, nor extortionists, will inherit God’s Kingdom.', pt: 'nem os ladrões, nem os avarentos, nem os bêbedos, nem os maldizentes, nem os roubadores herdarão o reino de Deus.' },
      { v: 11, en: 'Such were some of you, but you were washed. But you were sanctified. But you were justified in the name of the Lord Jesus, and in the Spirit of our God.', pt: 'E tais fostes alguns de vós; mas fostes lavados, mas fostes santificados, mas fostes justificados em nome do Senhor Jesus Cristo e no Espírito do nosso Deus.' },
      { v: 12, en: '“All things are lawful for me,” but not all things are expedient. “All things are lawful for me,” but I will not be brought under the power of anything.', pt: 'Todas as coisas me são lícitas, mas nem todas as coisas convêm. Todas as coisas me são lícitas; mas eu não me deixarei dominar por nenhuma delas.' },
      { v: 13, en: '“Foods for the belly, and the belly for foods,” but God will bring to nothing both it and them. But the body is not for sexual immorality, but for the Lord; and the Lord for the body.', pt: 'Os alimentos são para o estômago e o estômago para os alimentos; Deus, porém aniquilará, tanto um como os outros. Mas o corpo não é para a prostituição, mas para o Senhor, e o Senhor para o corpo.' },
      { v: 14, en: 'Now God raised up the Lord, and will also raise us up by his power.', pt: 'Ora, Deus não somente ressuscitou ao Senhor, mas também nos ressuscitará a nós pelo seu poder.' },
      { v: 15, en: 'Don’t you know that your bodies are members of Christ? Shall I then take the members of Christ, and make them members of a prostitute? May it never be!', pt: 'Não sabeis vós que os vossos corpos são membros de Cristo? Tomarei pois os membros de Cristo, e os farei membros de uma meretriz? De modo nenhum.' },
      { v: 16, en: 'Or don’t you know that he who is joined to a prostitute is one body? For, “The two”, he says, “will become one flesh.”', pt: 'Ou não sabeis que o que se une à meretriz, faz-se um corpo com ela? Porque, como foi dito, os dois serão uma só carne.' },
      { v: 17, en: 'But he who is joined to the Lord is one spirit.', pt: 'Mas, o que se une ao Senhor é um só espírito com ele.' },
      { v: 18, en: 'Flee sexual immorality! “Every sin that a man does is outside the body,” but he who commits sexual immorality sins against his own body.', pt: 'Fugi da prostituição. Qualquer outro pecado que o homem comete, é fora do corpo; mas o que se prostitui peca contra o seu próprio corpo.' },
      { v: 19, en: 'Or don’t you know that your body is a temple of the Holy Spirit who is in you, whom you have from God? You are not your own,', pt: 'Ou não sabeis que o vosso corpo é santuário do Espírito Santo, que habita em vós, o qual possuís da parte de Deus, e que não sois de vós mesmos?' },
      { v: 20, en: 'for you were bought with a price. Therefore glorify God in your body and in your spirit, which are God’s.', pt: 'Porque fostes comprados por preço; glorificai pois a Deus no vosso corpo.' },
    ],
    7: [
      { v: 1, en: 'Now concerning the things about which you wrote to me: it is good for a man not to touch a woman.', pt: 'Ora, quanto às coisas de que me escrevestes, bom seria que o homem não tocasse em mulher;' },
      { v: 2, en: 'But, because of sexual immoralities, let each man have his own wife, and let each woman have her own husband.', pt: 'mas, por causa da prostituição, tenha cada homem sua própria mulher e cada mulher seu próprio marido.' },
      { v: 3, en: 'Let the husband give his wife the affection owed her, and likewise also the wife her husband.', pt: 'O marido pague à mulher o que lhe é devido, e do mesmo modo a mulher ao marido.' },
      { v: 4, en: 'The wife doesn’t have authority over her own body, but the husband. Likewise also the husband doesn’t have authority over his own body, but the wife.', pt: 'A mulher não tem autoridade sobre o seu próprio corpo, mas sim o marido; e também da mesma sorte o marido não tem autoridade sobre o seu próprio corpo, mas sim a mulher.' },
      { v: 5, en: 'Don’t deprive one another, unless it is by consent for a season, that you may give yourselves to fasting and prayer, and may be together again, that Satan doesn’t tempt you because of your lack of self-control.', pt: 'Não vos negueis um ao outro, senão de comum acordo por algum tempo, a fim de vos aplicardes à oração e depois vos ajuntardes outra vez, para que Satanás não vos tente pela vossa incontinência.' },
      { v: 6, en: 'But this I say by way of concession, not of commandment.', pt: 'Digo isto, porém, como que por concessão e não por mandamento.' },
      { v: 7, en: 'Yet I wish that all men were like me. However each man has his own gift from God, one of this kind, and another of that kind.', pt: 'Contudo queria que todos os homens fossem como eu mesmo; mas cada um tem de Deus o seu próprio dom, um deste modo, e outro daquele.' },
      { v: 8, en: 'But I say to the unmarried and to widows, it is good for them if they remain even as I am.', pt: 'Digo, porém, aos solteiros e às viúvas, que lhes é bom se ficarem como eu.' },
      { v: 9, en: 'But if they don’t have self-control, let them marry. For it’s better to marry than to burn.', pt: 'Mas, se não podem conter-se, casem-se. Porque é melhor casar do que abrasar-se.' },
      { v: 10, en: 'But to the married I command—not I, but the Lord—that the wife not leave her husband', pt: 'Todavia, aos casados, mando, não eu mas o Senhor, que a mulher não se aparte do marido;' },
      { v: 11, en: '(but if she departs, let her remain unmarried, or else be reconciled to her husband), and that the husband not leave his wife.', pt: 'se, porém, se apartar, que fique sem casar, ou se reconcilie com o marido; e que o marido não deixe a mulher.' },
      { v: 12, en: 'But to the rest I—not the Lord—say, if any brother has an unbelieving wife, and she is content to live with him, let him not leave her.', pt: 'Mas aos outros digo eu, não o Senhor: Se algum irmão tem mulher incrédula, e ela consente em habitar com ele, não se separe dela.' },
      { v: 13, en: 'The woman who has an unbelieving husband, and he is content to live with her, let her not leave her husband.', pt: 'E se alguma mulher tem marido incrédulo, e ele consente em habitar com ela, não se separe dele.' },
      { v: 14, en: 'For the unbelieving husband is sanctified in the wife, and the unbelieving wife is sanctified in the husband. Otherwise your children would be unclean, but now they are holy.', pt: 'Porque o marido incrédulo é santificado pela mulher, e a mulher incrédula é santificada pelo marido crente; de outro modo, os vossos filhos seriam imundos; mas agora são santos.' },
      { v: 15, en: 'Yet if the unbeliever departs, let there be separation. The brother or the sister is not under bondage in such cases, but God has called us in peace.', pt: 'Mas, se o incrédulo se apartar, aparte-se; porque neste caso o irmão, ou a irmã, não está sujeito à servidão; pois Deus nos chamou em paz.' },
      { v: 16, en: 'For how do you know, wife, whether you will save your husband? Or how do you know, husband, whether you will save your wife?', pt: 'Pois, como sabes tu, ó mulher, se salvarás teu marido? ou, como sabes tu, ó marido, se salvarás tua mulher?' },
      { v: 17, en: 'Only, as the Lord has distributed to each man, as God has called each, so let him walk. So I command in all the assemblies.', pt: 'Somente ande cada um como o Senhor lhe repartiu, cada um como Deus o chamou. E é isso o que ordeno em todas as igrejas.' },
      { v: 18, en: 'Was anyone called having been circumcised? Let him not become uncircumcised. Has anyone been called in uncircumcision? Let him not be circumcised.', pt: 'Foi chamado alguém, estando circuncidado? permaneça assim. Foi alguém chamado na incircuncisão? não se circuncide.' },
      { v: 19, en: 'Circumcision is nothing, and uncircumcision is nothing, but the keeping of the commandments of God.', pt: 'A circuncisão nada é, e também a incircuncisão nada é, mas sim a observância dos mandamentos de Deus.' },
      { v: 20, en: 'Let each man stay in that calling in which he was called.', pt: 'Cada um fique no estado em que foi chamado.' },
      { v: 21, en: 'Were you called being a bondservant? Don’t let that bother you, but if you get an opportunity to become free, use it.', pt: 'Foste chamado sendo escravo? não te dê cuidado; mas se ainda podes tornar-te livre, aproveita a oportunidade.' },
      { v: 22, en: 'For he who was called in the Lord being a bondservant is the Lord’s free man. Likewise he who was called being free is Christ’s bondservant.', pt: 'Pois aquele que foi chamado no Senhor, mesmo sendo escravo, é um liberto do Senhor; e assim também o que foi chamado sendo livre, escravo é de Cristo.' },
      { v: 23, en: 'You were bought with a price. Don’t become bondservants of men.', pt: 'Por preço fostes comprados; mas vos façais escravos de homens.' },
      { v: 24, en: 'Brothers, let each man, in whatever condition he was called, stay in that condition with God.', pt: 'Irmãos, cada um fique diante de Deus no estado em que foi chamado.' },
      { v: 25, en: 'Now concerning virgins, I have no commandment from the Lord, but I give my judgment as one who has obtained mercy from the Lord to be trustworthy.', pt: 'Ora, quanto às virgens, não tenho mandamento do Senhor; dou, porém, o meu parecer, como quem tem alcançado misericórdia do Senhor para ser fiel.' },
      { v: 26, en: 'Therefore I think that because of the distress that is on us, that it’s good for a man to remain as he is.', pt: 'Acho, pois, que é bom, por causa da instante necessidade, que a pessoa fique como está.' },
      { v: 27, en: 'Are you bound to a wife? Don’t seek to be freed. Are you free from a wife? Don’t seek a wife.', pt: 'Estás ligado a mulher? não procures separação. Estás livre de mulher? não procures casamento.' },
      { v: 28, en: 'But if you marry, you have not sinned. If a virgin marries, she has not sinned. Yet such will have oppression in the flesh, and I want to spare you.', pt: 'Mas, se te casares, não pecaste; e, se a virgem se casar, não pecou. Todavia estes padecerão tribulação na carne e eu quisera poupar-vos.' },
      { v: 29, en: 'But I say this, brothers: the time is short, that from now on, both those who have wives may be as though they had none;', pt: 'Isto, porém, vos digo, irmãos, que o tempo se abrevia; pelo que, doravante, os que têm mulher sejam como se não a tivessem;' },
      { v: 30, en: 'and those who weep, as though they didn’t weep; and those who rejoice, as though they didn’t rejoice; and those who buy, as though they didn’t possess;', pt: 'os que choram, como se não chorassem; os que folgam, como se não folgassem; os que compram, como se não possuíssem;' },
      { v: 31, en: 'and those who use the world, as not using it to the fullest. For the mode of this world passes away.', pt: 'e os que usam deste mundo, como se dele não usassem em absoluto, porque a aparência deste mundo passa.' },
      { v: 32, en: 'But I desire to have you to be free from cares. He who is unmarried is concerned for the things of the Lord, how he may please the Lord;', pt: 'Pois quero que estejais livres de cuidado. Quem não é casado cuida das coisas do Senhor, em como há de agradar ao Senhor,' },
      { v: 33, en: 'but he who is married is concerned about the things of the world, how he may please his wife.', pt: 'mas quem é casado cuida das coisas do mundo, em como há de agradar a sua mulher,' },
      { v: 34, en: 'There is also a difference between a wife and a virgin. The unmarried woman cares about the things of the Lord, that she may be holy both in body and in spirit. But she who is married cares about the things of the world—how she may please her husband.', pt: 'e está dividido. A mulher não casada e a virgem cuidam das coisas do Senhor para serem santas, tanto no corpo como no espírito; a casada, porém, cuida das coisas do mundo, em como há de agradar ao marido.' },
      { v: 35, en: 'This I say for your own profit; not that I may ensnare you, but for that which is appropriate, and that you may attend to the Lord without distraction.', pt: 'E digo isto para proveito vosso; não para vos enredar, mas para o que é decente, e a fim de poderdes dedicar-vos ao Senhor sem distração alguma.' },
      { v: 36, en: 'But if any man thinks that he is behaving inappropriately toward his virgin, if she is past the flower of her age, and if need so requires, let him do what he desires. He doesn’t sin. Let them marry.', pt: 'Mas, se alguém julgar que lhe é desairoso conservar solteira a sua filha donzela, se ela estiver passando da idade de se casar, e se for necessário, faça o que quiser; não peca; casem-se.' },
      { v: 37, en: 'But he who stands steadfast in his heart, having no urgency, but has power over his own will, and has determined in his own heart to keep his own virgin, does well.', pt: 'Todavia aquele que está firme em seu coração, não tendo necessidade, mas tendo domínio sobre a sua própria vontade, se resolver no seu coração guardar virgem sua filha, fará bem.' },
      { v: 38, en: 'So then both he who gives his own virgin in marriage does well, and he who doesn’t give her in marriage does better.', pt: 'De modo que aquele que dá em casamento a sua filha donzela, faz bem; mas o que não a der, fará melhor.' },
      { v: 39, en: 'A wife is bound by law for as long as her husband lives; but if the husband is dead, she is free to be married to whomever she desires, only in the Lord.', pt: 'A mulher está ligada enquanto o marido vive; mas se falecer o marido, fica livre para casar com quem quiser, contanto que seja no Senhor.' },
      { v: 40, en: 'But she is happier if she stays as she is, in my judgment, and I think that I also have God’s Spirit.', pt: 'Será, porém, mais feliz se permanecer como está, segundo o meu parecer, e eu penso que também tenho o Espírito de Deus.' },
    ],
    8: [
      { v: 1, en: 'Now concerning things sacrificed to idols: We know that we all have knowledge. Knowledge puffs up, but love builds up.', pt: 'Ora, no tocante às coisas sacrificadas aos ídolos, sabemos que todos temos ciência. A ciência incha, mas o amor edifica.' },
      { v: 2, en: 'But if anyone thinks that he knows anything, he doesn’t yet know as he ought to know.', pt: 'Se alguém cuida saber alguma coisa, ainda não sabe como convém saber.' },
      { v: 3, en: 'But if anyone loves God, the same is known by him.', pt: 'Mas, se alguém ama a Deus, esse é conhececido dele.' },
      { v: 4, en: 'Therefore concerning the eating of things sacrificed to idols, we know that no idol is anything in the world, and that there is no other God but one.', pt: 'Quanto, pois, ao comer das coisas sacrificadas aos ídolos, sabemos que o ídolo nada é no mundo, e que não há outro Deus, senão um só.' },
      { v: 5, en: 'For though there are things that are called “gods”, whether in the heavens or on earth; as there are many “gods” and many “lords”;', pt: 'Pois, ainda que haja também alguns que se chamem deuses, quer no céu quer na terra (como há muitos deuses e muitos senhores),' },
      { v: 6, en: 'yet to us there is one God, the Father, of whom are all things, and we for him; and one Lord, Jesus Christ, through whom are all things, and we live through him.', pt: 'todavia para nós há um só Deus, o Pai, de quem são todas as coisas e para quem nós vivemos; e um só Senhor, Jesus Cristo, pelo qual existem todas as coisas, e por ele nós também.' },
      { v: 7, en: 'However, that knowledge isn’t in all men. But some, with consciousness of the idol until now, eat as of a thing sacrificed to an idol, and their conscience, being weak, is defiled.', pt: 'Entretanto, nem em todos há esse conhecimento; pois alguns há que, acostumados até agora com o ídolo, comem como de coisas sacrificadas a um ídolo; e a sua consciência, sendo fraca, contamina-se.' },
      { v: 8, en: 'But food will not commend us to God. For neither, if we don’t eat, are we the worse; nor, if we eat, are we the better.', pt: 'Não é, porém, a comida que nos há de recomendar a Deus; pois não somos piores se não comermos, nem melhores se comermos.' },
      { v: 9, en: 'But be careful that by no means does this liberty of yours become a stumbling block to the weak.', pt: 'Mas, vede que essa liberdade vossa não venha a ser motivo de tropeço para os fracos.' },
      { v: 10, en: 'For if a man sees you who have knowledge sitting in an idol’s temple, won’t his conscience, if he is weak, be emboldened to eat things sacrificed to idols?', pt: 'Porque, se alguém te vir a ti, que tens ciência, reclinado à mesa em templo de ídolos, não será induzido, sendo a sua consciência fraca, a comer das coisas sacrificadas aos ídolos?' },
      { v: 11, en: 'And through your knowledge, he who is weak perishes, the brother for whose sake Christ died.', pt: 'Pela tua ciência, pois, perece aquele que é fraco, o teu irmão por quem Cristo morreu.' },
      { v: 12, en: 'Thus, sinning against the brothers, and wounding their conscience when it is weak, you sin against Christ.', pt: 'Ora, pecando assim contra os irmãos, e ferindo-lhes a consciência quando fraca, pecais contra Cristo.' },
      { v: 13, en: 'Therefore if food causes my brother to stumble, I will eat no meat forever more, that I don’t cause my brother to stumble.', pt: 'Pelo que, se a comida fizer tropeçar a meu irmão, nunca mais comerei carne, para não servir de tropeço a meu irmão.' },
    ],
    9: [
      { v: 1, en: 'Am I not free? Am I not an apostle? Haven’t I seen Jesus Christ, our Lord? Aren’t you my work in the Lord?', pt: 'Não sou eu livre? Não sou apóstolo? Não vi eu a Jesus nosso Senhor? Não sois vós obra minha no Senhor?' },
      { v: 2, en: 'If to others I am not an apostle, yet at least I am to you; for you are the seal of my apostleship in the Lord.', pt: 'Se eu não sou apóstolo para os outros, ao menos para vós o sou; porque vós sois o selo do meu apostolado no Senhor.' },
      { v: 3, en: 'My defense to those who examine me is this.', pt: 'Esta é a minha defesa para com os que me acusam.' },
      { v: 4, en: 'Have we no right to eat and to drink?', pt: 'Não temos nós direito de comer e de beber?' },
      { v: 5, en: 'Have we no right to take along a wife who is a believer, even as the rest of the apostles, and the brothers of the Lord, and Cephas?', pt: 'Não temos nós direito de levar conosco esposa crente, como também os demais apóstolos, e os irmãos do Senhor, e Cefas?' },
      { v: 6, en: 'Or have only Barnabas and I no right to not work?', pt: 'Ou será que só eu e Barnabé não temos direito de deixar de trabalhar?' },
      { v: 7, en: 'What soldier ever serves at his own expense? Who plants a vineyard, and doesn’t eat of its fruit? Or who feeds a flock, and doesn’t drink from the flock’s milk?', pt: 'Quem jamais vai à guerra à sua própria custa? Quem planta uma vinha e não come do seu fruto? Ou quem apascenta um rebanho e não se alimenta do leite do rebanho?' },
      { v: 8, en: 'Do I speak these things according to the ways of men? Or doesn’t the law also say the same thing?', pt: 'Porventura digo eu isto como homem? Ou não diz a lei também o mesmo?' },
      { v: 9, en: 'For it is written in the law of Moses, “You shall not muzzle an ox while it treads out the grain.” Is it for the oxen that God cares,', pt: 'Pois na lei de Moisés está escrito: Não atarás a boca do boi quando debulha. Porventura está Deus cuidando dos bois?' },
      { v: 10, en: 'or does he say it assuredly for our sake? Yes, it was written for our sake, because he who plows ought to plow in hope, and he who threshes in hope should partake of his hope.', pt: 'Ou não o diz certamente por nós? Com efeito, é por amor de nós que está escrito; porque o que lavra deve debulhar com esperança de participar do fruto.' },
      { v: 11, en: 'If we sowed to you spiritual things, is it a great thing if we reap your fleshly things?', pt: 'Se nós semeamos para vós as coisas espirituais, será muito que de vós colhamos as materias?' },
      { v: 12, en: 'If others partake of this right over you, don’t we yet more? Nevertheless we did not use this right, but we bear all things, that we may cause no hindrance to the Good News of Christ.', pt: 'Se outros participam deste direito sobre vós, por que não nós com mais justiça? Mas nós nunca usamos deste direito; antes suportamos tudo, para não pormos impedimento algum ao evangelho de Cristo.' },
      { v: 13, en: 'Don’t you know that those who serve around sacred things eat from the things of the temple, and those who wait on the altar have their portion with the altar?', pt: 'Não sabeis vós que os que administram o que é sagrado comem do que é do templo? E que os que servem ao altar, participam do altar?' },
      { v: 14, en: 'Even so the Lord ordained that those who proclaim the Good News should live from the Good News.', pt: 'Assim ordenou também o Senhor aos que anunciam o evangelho, que vivam do evangelho.' },
      { v: 15, en: 'But I have used none of these things, and I don’t write these things that it may be done so in my case; for I would rather die, than that anyone should make my boasting void.', pt: 'Mas eu de nenhuma destas coisas tenho usado. Nem escrevo isto para que assim se faça comigo; porque melhor me fora morrer, do que alguém fazer vã esta minha glória.' },
      { v: 16, en: 'For if I preach the Good News, I have nothing to boast about; for necessity is laid on me; but woe is to me, if I don’t preach the Good News.', pt: 'Pois, se anuncio o evangelho, não tenho de que me gloriar, porque me é imposta essa obrigação; e ai de mim, se não anunciar o evangelho!' },
      { v: 17, en: 'For if I do this of my own will, I have a reward. But if not of my own will, I have a stewardship entrusted to me.', pt: 'Se, pois, o faço de vontade própria, tenho recompensa; mas, se não é de vontade própria, estou apenas incumbido de uma mordomia.' },
      { v: 18, en: 'What then is my reward? That, when I preach the Good News, I may present the Good News of Christ without charge, so as not to abuse my authority in the Good News.', pt: 'Logo, qual é a minha recompensa? É que, pregando o evangelho, eu o faça gratuitamente, para não usar em absoluto do meu direito no evangelho.' },
      { v: 19, en: 'For though I was free from all, I brought myself under bondage to all, that I might gain the more.', pt: 'Pois, sendo livre de todos, fiz-me escravo de todos para ganhar o maior número possível:' },
      { v: 20, en: 'To the Jews I became as a Jew, that I might gain Jews; to those who are under the law, as under the law, that I might gain those who are under the law;', pt: 'Fiz-me como judeu para os judeus, para ganhar os judeus; para os que estão debaixo da lei, como se estivesse eu debaixo da lei (embora debaixo da lei não esteja), para ganhar os que estão debaixo da lei;' },
      { v: 21, en: 'to those who are without law, as without law (not being without law toward God, but under law toward Christ), that I might win those who are without law.', pt: 'para os que estão sem lei, como se estivesse sem lei (não estando sem lei para com Deus, mas debaixo da lei de Cristo), para ganhar os que estão sem lei.' },
      { v: 22, en: 'To the weak I became as weak, that I might gain the weak. I have become all things to all men, that I may by all means save some.', pt: 'Fiz-me como fraco para os fracos, para ganhar os fracos. Fiz-me tudo para todos, para por todos os meios chegar a salvar alguns.' },
      { v: 23, en: 'Now I do this for the sake of the Good News, that I may be a joint partaker of it.', pt: 'Ora, tudo faço por causa do evangelho, para dele tornar-me co-participante.' },
      { v: 24, en: 'Don’t you know that those who run in a race all run, but one receives the prize? Run like that, that you may win.', pt: 'Não sabeis vós que os que correm no estádio, todos, na verdade, correm, mas um só é que recebe o prêmio? Correi de tal maneira que o alcanceis.' },
      { v: 25, en: 'Every man who strives in the games exercises self-control in all things. Now they do it to receive a corruptible crown, but we an incorruptible.', pt: 'E todo aquele que luta, exerce domínio próprio em todas as coisas; ora, eles o fazem para alcançar uma coroa corruptível, nós, porém, uma incorruptível.' },
      { v: 26, en: 'I therefore run like that, not aimlessly. I fight like that, not beating the air,', pt: 'Pois eu assim corro, não como indeciso; assim combato, não como batendo no ar.' },
      { v: 27, en: 'but I beat my body and bring it into submission, lest by any means, after I have preached to others, I myself should be rejected.', pt: 'Antes subjugo o meu corpo, e o reduzo à submissão, para que, depois de pregar a outros, eu mesmo não venha a ficar reprovado.' },
    ],
    10: [
      { v: 1, en: 'Now I would not have you ignorant, brothers, that our fathers were all under the cloud, and all passed through the sea;', pt: 'Pois não quero, irmãos, que ignoreis que nossos pais estiveram todos debaixo da nuvem, e todos passaram pelo mar;' },
      { v: 2, en: 'and were all baptized into Moses in the cloud and in the sea;', pt: 'e, na nuvem e no mar, todos foram batizados em Moisés,' },
      { v: 3, en: 'and all ate the same spiritual food;', pt: 'e todos comeram do mesmo alimento espiritual;' },
      { v: 4, en: 'and all drank the same spiritual drink. For they drank of a spiritual rock that followed them, and the rock was Christ.', pt: 'e beberam todos da mesma bebida espiritual, porque bebiam da pedra espiritual que os acompanhava; e a pedra era Cristo.' },
      { v: 5, en: 'However with most of them, God was not well pleased, for they were overthrown in the wilderness.', pt: 'Mas Deus não se agradou da maior parte deles; pelo que foram prostrados no deserto.' },
      { v: 6, en: 'Now these things were our examples, to the intent we should not lust after evil things, as they also lusted.', pt: 'Ora, estas coisas nos foram feitas para exemplo, a fim de que não cobicemos as coisas más, como eles cobiçaram.' },
      { v: 7, en: 'Don’t be idolaters, as some of them were. As it is written, “The people sat down to eat and drink, and rose up to play.”', pt: 'Não vos torneis, pois, idólatras, como alguns deles, conforme está escrito: O povo assentou-se a comer e a beber, e levantou-se para folgar.' },
      { v: 8, en: 'Let us not commit sexual immorality, as some of them committed, and in one day twenty-three thousand fell.', pt: 'Nem nos prostituamos, como alguns deles fizeram; e caíram num só dia vinte e três mil.' },
      { v: 9, en: 'Let us not test Christ, as some of them tested, and perished by the serpents.', pt: 'E não tentemos o Senhor, como alguns deles o tentaram, e pereceram pelas serpentes.' },
      { v: 10, en: 'Don’t grumble, as some of them also grumbled, and perished by the destroyer.', pt: 'E não murmureis, como alguns deles murmuraram, e pereceram pelo destruidor.' },
      { v: 11, en: 'Now all these things happened to them by way of example, and they were written for our admonition, on whom the ends of the ages have come.', pt: 'Ora, tudo isto lhes acontecia como exemplo, e foi escrito para aviso nosso, para quem já são chegados os fins dos séculos.' },
      { v: 12, en: 'Therefore let him who thinks he stands be careful that he doesn’t fall.', pt: 'Aquele, pois, que pensa estar em pé, olhe não caia.' },
      { v: 13, en: 'No temptation has taken you except what is common to man. God is faithful, who will not allow you to be tempted above what you are able, but will with the temptation also make the way of escape, that you may be able to endure it.', pt: 'Não vos sobreveio nenhuma tentação, senão humana; mas fiel é Deus, o qual não deixará que sejais tentados acima do que podeis resistir, antes com a tentação dará também o meio de saída, para que a possais suportar.' },
      { v: 14, en: 'Therefore, my beloved, flee from idolatry.', pt: 'Portanto, meus amados, fugi da idolatria.' },
      { v: 15, en: 'I speak as to wise men. Judge what I say.', pt: 'Falo como a entendidos; julgai vós mesmos o que digo.' },
      { v: 16, en: 'The cup of blessing which we bless, isn’t it a sharing of the blood of Christ? The bread which we break, isn’t it a sharing of the body of Christ?', pt: 'Porventura o cálice de bênção que abençoamos, não é a comunhão do sangue de Cristo? O pão que partimos, não é porventura a comunhão do corpo de Cristo?' },
      { v: 17, en: 'Because there is one loaf of bread, we, who are many, are one body; for we all partake of the one loaf of bread.', pt: 'Pois nós, embora muitos, somos um só pão, um só corpo; porque todos participamos de um mesmo pão.' },
      { v: 18, en: 'Consider Israel according to the flesh. Don’t those who eat the sacrifices participate in the altar?', pt: 'Vede a Israel segundo a carne; os que comem dos sacrifícios não são porventura participantes do altar?' },
      { v: 19, en: 'What am I saying then? That a thing sacrificed to idols is anything, or that an idol is anything?', pt: 'Mas que digo? Que o sacrificado ao ídolo é alguma coisa? Ou que o ídolo é alguma coisa?' },
      { v: 20, en: 'But I say that the things which the Gentiles sacrifice, they sacrifice to demons, and not to God, and I don’t desire that you would have fellowship with demons.', pt: 'Antes digo que as coisas que eles sacrificam, sacrificam-nas a demônios, e não a Deus. E não quero que sejais participantes com os demônios.' },
      { v: 21, en: 'You can’t both drink the cup of the Lord and the cup of demons. You can’t both partake of the table of the Lord, and of the table of demons.', pt: 'Não podeis beber do cálice do Senhor e do cálice de demônios; não podeis participar da mesa do Senhor e da mesa de demônios.' },
      { v: 22, en: 'Or do we provoke the Lord to jealousy? Are we stronger than he?', pt: 'Ou provocaremos a zelos o Senhor? Somos, porventura, mais fortes do que ele?' },
      { v: 23, en: '“All things are lawful for me,” but not all things are profitable. “All things are lawful for me,” but not all things build up.', pt: 'Todas as coisas são lícitas, mas nem todas as coisas convêm; todas as coisas são lícitas, mas nem todas as coisas edificam.' },
      { v: 24, en: 'Let no one seek his own, but each one his neighbor’s good.', pt: 'Ninguém busque o proveito próprio, antes cada um o de outrem.' },
      { v: 25, en: 'Whatever is sold in the butcher shop, eat, asking no question for the sake of conscience,', pt: 'Comei de tudo quanto se vende no mercado, nada perguntando por causa da consciência.' },
      { v: 26, en: 'for “the earth is the Lord’s, and its fullness.”', pt: 'Pois do Senhor é a terra e a sua plenitude.' },
      { v: 27, en: 'But if one of those who don’t believe invites you to a meal, and you are inclined to go, eat whatever is set before you, asking no questions for the sake of conscience.', pt: 'Se, portanto, algum dos incrédulos vos convidar, e quiserdes ir, comei de tudo o que se puser diante de vós, nada perguntando por causa da consciência.' },
      { v: 28, en: 'But if anyone says to you, “This was offered to idols,” don’t eat it for the sake of the one who told you, and for the sake of conscience. For “the earth is the Lord’s, and all its fullness.”', pt: 'Mas, se alguém vos disser: Isto foi oferecido em sacrifício; não comais por causa daquele que vos advertiu e por causa da consciência;' },
      { v: 29, en: 'Conscience, I say, not your own, but the other’s conscience. For why is my liberty judged by another conscience?', pt: 'consciência, digo, não a tua, mas a do outro. Pois, por que há de ser julgada a minha liberdade pela consciência de outrem?' },
      { v: 30, en: 'If I partake with thankfulness, why am I denounced for something I give thanks for?', pt: 'E, se eu com gratidão participo, por que sou vilipendiado por causa daquilo por que dou graças?' },
      { v: 31, en: 'Whether therefore you eat, or drink, or whatever you do, do all to the glory of God.', pt: 'Portanto, quer comais quer bebais, ou façais, qualquer outra coisa, fazei tudo para glória de Deus.' },
      { v: 32, en: 'Give no occasion for stumbling, either to Jews, or to Greeks, or to the assembly of God;', pt: 'Não vos torneis causa de tropeço nem a judeus, nem a gregos, nem a igreja de Deus;' },
      { v: 33, en: 'even as I also please all men in all things, not seeking my own profit, but the profit of the many, that they may be saved.', pt: 'assim como também eu em tudo procuro agradar a todos, não buscando o meu próprio proveito, mas o de muitos, para que sejam salvos.' },
    ],
    11: [
      { v: 1, en: 'Be imitators of me, even as I also am of Christ.', pt: 'Sede meus imitadores, como também eu o sou de Cristo.' },
      { v: 2, en: 'Now I praise you, brothers, that you remember me in all things, and hold firm the traditions, even as I delivered them to you.', pt: 'Ora, eu vos louvo, porque em tudo vos lembrais de mim, e guardais os preceitos assim como vo-los entreguei.' },
      { v: 3, en: 'But I would have you know that the head of every man is Christ, and the head of the woman is man, and the head of Christ is God.', pt: 'Quero porém, que saibais que Cristo é a cabeça de todo homem, o homem a cabeça da mulher, e Deus a cabeça de Cristo.' },
      { v: 4, en: 'Every man praying or prophesying, having his head covered, dishonors his head.', pt: 'Todo homem que ora ou profetiza com a cabeça coberta desonra a sua cabeça.' },
      { v: 5, en: 'But every woman praying or prophesying with her head uncovered dishonors her head. For it is one and the same thing as if she were shaved.', pt: 'Mas toda mulher que ora ou profetiza com a cabeça descoberta desonra a sua cabeça, porque é a mesma coisa como se estivesse rapada.' },
      { v: 6, en: 'For if a woman is not covered, let her hair also be cut off. But if it is shameful for a woman to have her hair cut off or be shaved, let her be covered.', pt: 'Portanto, se a mulher não se cobre com véu, tosquie-se também; se, porém, para a mulher é vergonhoso ser tosquiada ou rapada, cubra-se com véu.' },
      { v: 7, en: 'For a man indeed ought not to have his head covered, because he is the image and glory of God, but the woman is the glory of the man.', pt: 'Pois o homem, na verdade, não deve cobrir a cabeça, porque é a imagem e glória de Deus; mas a mulher é a glória do homem.' },
      { v: 8, en: 'For man is not from woman, but woman from man;', pt: 'Porque o homem não proveio da mulher, mas a mulher do homem;' },
      { v: 9, en: 'for man wasn’t created for the woman, but woman for the man.', pt: 'nem foi o homem criado por causa da mulher, mas sim, a mulher por causa do homem.' },
      { v: 10, en: 'For this cause the woman ought to have authority over her own head, because of the angels.', pt: 'Portanto, a mulher deve trazer sobre a cabeça um sinal de submissão, por causa dos anjos.' },
      { v: 11, en: 'Nevertheless, neither is the woman independent of the man, nor the man independent of the woman, in the Lord.', pt: 'Todavia, no Senhor, nem a mulher é independente do homem, nem o homem é independente da mulher.' },
      { v: 12, en: 'For as woman came from man, so a man also comes through a woman; but all things are from God.', pt: 'pois, assim como a mulher veio do homem, assim também o homem nasce da mulher, mas tudo vem de Deus.' },
      { v: 13, en: 'Judge for yourselves. Is it appropriate that a woman pray to God unveiled?', pt: 'julgai entre vós mesmos: é conveniente que uma mulher com a cabeça descoberta ore a Deus?' },
      { v: 14, en: 'Doesn’t even nature itself teach you that if a man has long hair, it is a dishonor to him?', pt: 'Não vos ensina a própria natureza que se o homem tiver cabelo comprido, é para ele uma desonra;' },
      { v: 15, en: 'But if a woman has long hair, it is a glory to her, for her hair is given to her for a covering.', pt: 'mas se a mulher tiver o cabelo comprido, é para ela uma glória? Pois a cabeleira lhe foi dada em lugar de véu.' },
      { v: 16, en: 'But if any man seems to be contentious, we have no such custom, neither do God’s assemblies.', pt: 'Mas, se alguém quiser ser contencioso, nós não temos tal costume, nem tampouco as igrejas de Deus.' },
      { v: 17, en: 'But in giving you this command, I don’t praise you, that you come together not for the better but for the worse.', pt: 'Nisto, porém, que vou dizer-vos não vos louvo; porquanto vos ajuntais, não para melhor, mas para pior.' },
      { v: 18, en: 'For first of all, when you come together in the assembly, I hear that divisions exist among you, and I partly believe it.', pt: 'Porque, antes de tudo, ouço que quando vos ajuntais na igreja há entre vós dissensões; e em parte o creio.' },
      { v: 19, en: 'For there also must be factions among you, that those who are approved may be revealed among you.', pt: 'E até importa que haja entre vós facções, para que os aprovados se tornem manifestos entre vós.' },
      { v: 20, en: 'When therefore you assemble yourselves together, it is not the Lord’s supper that you eat.', pt: 'De sorte que, quando vos ajuntais num lugar, não é para comer a ceia do Senhor;' },
      { v: 21, en: 'For in your eating each one takes his own supper first. One is hungry, and another is drunken.', pt: 'porque quando comeis, cada um toma antes de outrem a sua própria ceia; e assim um fica com fome e outro se embriaga.' },
      { v: 22, en: 'What, don’t you have houses to eat and to drink in? Or do you despise God’s assembly, and put them to shame who don’t have enough? What shall I tell you? Shall I praise you? In this I don’t praise you.', pt: 'Não tendes porventura casas onde comer e beber? Ou desprezais a igreja de Deus, e envergonhais os que nada têm? Que vos direi? Louvar-vos-ei? Nisto não vos louvo.' },
      { v: 23, en: 'For I received from the Lord that which also I delivered to you, that the Lord Jesus on the night in which he was betrayed took bread.', pt: 'Porque eu recebi do Senhor o que também vos entreguei: que o Senhor Jesus, na noite em que foi traído, tomou pão;' },
      { v: 24, en: 'When he had given thanks, he broke it, and said, “Take, eat. This is my body, which is broken for you. Do this in memory of me.”', pt: 'e, havendo dado graças, o partiu e disse: Isto é o meu corpo que é por vós; fazei isto em memória de mim.' },
      { v: 25, en: 'In the same way he also took the cup, after supper, saying, “This cup is the new covenant in my blood. Do this, as often as you drink, in memory of me.”', pt: 'Semelhantemente também, depois de cear, tomou o cálice, dizendo: Este cálice é o novo pacto no meu sangue; fazei isto, todas as vezes que o beberdes, em memória de mim.' },
      { v: 26, en: 'For as often as you eat this bread and drink this cup, you proclaim the Lord’s death until he comes.', pt: 'Porque todas as vezes que comerdes deste pão e beberdes do cálice estareis anunciando a morte do Senhor, até que ele venha.' },
      { v: 27, en: 'Therefore whoever eats this bread or drinks the Lord’s cup in a way unworthy of the Lord will be guilty of the body and the blood of the Lord.', pt: 'De modo que qualquer que comer do pão, ou beber do cálice do Senhor indignamente, será culpado do corpo e do sangue do Senhor.' },
      { v: 28, en: 'But let a man examine himself, and so let him eat of the bread, and drink of the cup.', pt: 'Examine-se, pois, o homem a si mesmo, e assim coma do pão e beba do cálice.' },
      { v: 29, en: 'For he who eats and drinks in an unworthy way eats and drinks judgment to himself, if he doesn’t discern the Lord’s body.', pt: 'Porque quem come e bebe, come e bebe para sua própria condenação, se não discernir o corpo do Senhor.' },
      { v: 30, en: 'For this cause many among you are weak and sickly, and not a few sleep.', pt: 'Por causa disto há entre vós muitos fracos e enfermos, e muitos que dormem.' },
      { v: 31, en: 'For if we discerned ourselves, we wouldn’t be judged.', pt: 'Mas, se nós nos julgássemos a nós mesmos, não seríamos julgados;' },
      { v: 32, en: 'But when we are judged, we are punished by the Lord, that we may not be condemned with the world.', pt: 'quando, porém, somos julgados pelo Senhor, somos corrigidos, para não sermos condenados com o mundo.' },
      { v: 33, en: 'Therefore, my brothers, when you come together to eat, wait for one another.', pt: 'Portanto, meus irmãos, quando vos ajuntais para comer, esperai uns pelos outros.' },
      { v: 34, en: 'But if anyone is hungry, let him eat at home, lest your coming together be for judgment. The rest I will set in order whenever I come.', pt: 'Se algum tiver fome, coma em casa, a fim de que não vos reunais para condenação vossa. E as demais coisas eu as ordenarei quando for.' },
    ],
    12: [
      { v: 1, en: 'Now concerning spiritual things, brothers, I don’t want you to be ignorant.', pt: 'Ora, a respeito dos dons espirituais, não quero, irmãos, que sejais ignorantes.' },
      { v: 2, en: 'You know that when you were heathen, you were led away to those mute idols, however you might be led.', pt: 'Vós sabeis que, quando éreis gentios, vos desviáveis para os ídolos mudos, conforme éreis levados.' },
      { v: 3, en: 'Therefore I make known to you that no man speaking by God’s Spirit says, “Jesus is accursed.” No one can say, “Jesus is Lord,” but by the Holy Spirit.', pt: 'Portanto vos quero fazer compreender que ninguém, falando pelo Espírito de Deus, diz: Jesus é anátema! e ninguém pode dizer: Jesus é o Senhor! senão pelo Espírito Santo.' },
      { v: 4, en: 'Now there are various kinds of gifts, but the same Spirit.', pt: 'Ora, há diversidade de dons, mas o Espírito é o mesmo.' },
      { v: 5, en: 'There are various kinds of service, and the same Lord.', pt: 'E há diversidade de ministérios, mas o Senhor é o mesmo.' },
      { v: 6, en: 'There are various kinds of workings, but the same God, who works all things in all.', pt: 'E há diversidade de operações, mas é o mesmo Deus que opera tudo em todos.' },
      { v: 7, en: 'But to each one is given the manifestation of the Spirit for the profit of all.', pt: 'A cada um, porém, é dada a manifestação do Espírito para o proveito comum.' },
      { v: 8, en: 'For to one is given through the Spirit the word of wisdom, and to another the word of knowledge, according to the same Spirit;', pt: 'Porque a um, pelo Espírito, é dada a palavra da sabedoria; a outro, pelo mesmo Espírito, a palavra da ciência;' },
      { v: 9, en: 'to another faith, by the same Spirit; and to another gifts of healings, by the same Spirit;', pt: 'a outro, pelo mesmo Espírito, a fé; a outro, pelo mesmo Espírito, os dons de curar;' },
      { v: 10, en: 'and to another workings of miracles; and to another prophecy; and to another discerning of spirits; to another different kinds of languages; and to another the interpretation of languages.', pt: 'a outro a operação de milagres; a outro a profecia; a outro o dom de discernir espíritos; a outro a variedade de línguas; e a outro a interpretação de línguas.' },
      { v: 11, en: 'But the one and the same Spirit produces all of these, distributing to each one separately as he desires.', pt: 'Mas um só e o mesmo Espírito opera todas estas coisas, distribuindo particularmente a cada um como quer.' },
      { v: 12, en: 'For as the body is one, and has many members, and all the members of the body, being many, are one body; so also is Christ.', pt: 'Porque, assim como o corpo é um, e tem muitos membros, e todos os membros do corpo, embora muitos, formam um só corpo, assim também é Cristo.' },
      { v: 13, en: 'For in one Spirit we were all baptized into one body, whether Jews or Greeks, whether bond or free; and were all given to drink into one Spirit.', pt: 'Pois em um só Espírito fomos todos nós batizados em um só corpo, quer judeus, quer gregos, quer escravos quer livres; e a todos nós foi dado beber de um só Espírito.' },
      { v: 14, en: 'For the body is not one member, but many.', pt: 'Porque também o corpo não é um membro, mas muitos.' },
      { v: 15, en: 'If the foot would say, “Because I’m not the hand, I’m not part of the body,” it is not therefore not part of the body.', pt: 'Se o pé disser: Porque não sou mão, não sou do corpo; nem por isso deixará de ser do corpo.' },
      { v: 16, en: 'If the ear would say, “Because I’m not the eye, I’m not part of the body,” it’s not therefore not part of the body.', pt: 'E se a orelha disser: Porque não sou olho, não sou do corpo; nem por isso deixará de ser do corpo.' },
      { v: 17, en: 'If the whole body were an eye, where would the hearing be? If the whole were hearing, where would the smelling be?', pt: 'Se o corpo todo fosse olho, onde estaria o ouvido? Se todo fosse ouvido, onde estaria o olfato?' },
      { v: 18, en: 'But now God has set the members, each one of them, in the body, just as he desired.', pt: 'Mas agora Deus colocou os membros no corpo, cada um deles como quis.' },
      { v: 19, en: 'If they were all one member, where would the body be?', pt: 'E, se todos fossem um só membro, onde estaria o corpo?' },
      { v: 20, en: 'But now they are many members, but one body.', pt: 'Agora, porém, há muitos membros, mas um só corpo.' },
      { v: 21, en: 'The eye can’t tell the hand, “I have no need for you,” or again the head to the feet, “I have no need for you.”', pt: 'E o olho não pode dizer à mão: Não tenho necessidade de ti; nem ainda a cabeça aos pés: Não tenho necessidade de vós.' },
      { v: 22, en: 'No, much rather, those members of the body which seem to be weaker are necessary.', pt: 'Antes, os membros do corpo que parecem ser mais fracos são necessários;' },
      { v: 23, en: 'Those parts of the body which we think to be less honorable, on those we bestow more abundant honor; and our unpresentable parts have more abundant propriety;', pt: 'e os membros do corpo que reputamos serem menos honrados, a esses revestimos com muito mais honra; e os que em nós não são decorosos têm muito mais decoro,' },
      { v: 24, en: 'whereas our presentable parts have no such need. But God composed the body together, giving more abundant honor to the inferior part,', pt: 'ao passo que os decorosos não têm necessidade disso. Mas Deus assim formou o corpo, dando muito mais honra ao que tinha falta dela,' },
      { v: 25, en: 'that there should be no division in the body, but that the members should have the same care for one another.', pt: 'para que não haja divisão no corpo, mas que os membros tenham igual cuidado uns dos outros.' },
      { v: 26, en: 'When one member suffers, all the members suffer with it. Or when one member is honored, all the members rejoice with it.', pt: 'De maneira que, se um membro padece, todos os membros padecem com ele; e, se um membro é honrado, todos os membros se regozijam com ele.' },
      { v: 27, en: 'Now you are the body of Christ, and members individually.', pt: 'Ora, vós sois corpo de Cristo, e individualmente seus membros.' },
      { v: 28, en: 'God has set some in the assembly: first apostles, second prophets, third teachers, then miracle workers, then gifts of healings, helps, governments, and various kinds of languages.', pt: 'E a uns pôs Deus na igreja, primeiramente apóstolos, em segundo lugar profetas, em terceiro mestres, depois operadores de milagres, depois dons de curar, socorros, governos, variedades de línguas.' },
      { v: 29, en: 'Are all apostles? Are all prophets? Are all teachers? Are all miracle workers?', pt: 'Porventura são todos apóstolos? são todos profetas? são todos mestres? são todos operadores de milagres?' },
      { v: 30, en: 'Do all have gifts of healings? Do all speak with various languages? Do all interpret?', pt: 'Todos têm dons de curar? falam todos em línguas? interpretam todos?' },
      { v: 31, en: 'But earnestly desire the best gifts. Moreover, I show a most excellent way to you.', pt: 'Mas procurai com zelo os maiores dons. Ademais, eu vos mostrarei um caminho sobremodo excelente.' },
    ],
    13: [
      { v: 1, en: 'If I speak with the languages of men and of angels, but don’t have love, I have become sounding brass, or a clanging cymbal.', pt: 'Ainda que eu falasse as línguas dos homens e dos anjos, e não tivesse amor, seria como o metal que soa ou como o címbalo que retine.' },
      { v: 2, en: 'If I have the gift of prophecy, and know all mysteries and all knowledge; and if I have all faith, so as to remove mountains, but don’t have love, I am nothing.', pt: 'E ainda que tivesse o dom de profecia, e conhecesse todos os mistérios e toda a ciência, e ainda que tivesse toda fé, de maneira tal que transportasse os montes, e não tivesse amor, nada seria.' },
      { v: 3, en: 'If I give away all my goods to feed the poor, and if I give my body to be burned, but don’t have love, it profits me nothing.', pt: 'E ainda que distribuísse todos os meus bens para sustento dos pobres, e ainda que entregasse o meu corpo para ser queimado, e não tivesse amor, nada disso me aproveitaria.' },
      { v: 4, en: 'Love is patient and is kind; love doesn’t envy. Love doesn’t brag, is not proud,', pt: 'O amor é sofredor, é benigno; o amor não é invejoso; o amor não se vangloria, não se ensoberbece,' },
      { v: 5, en: 'doesn’t behave itself inappropriately, doesn’t seek its own way, is not provoked, takes no account of evil;', pt: 'não se porta inconvenientemente, não busca os seus próprios interesses, não se irrita, não suspeita mal;' },
      { v: 6, en: 'doesn’t rejoice in unrighteousness, but rejoices with the truth;', pt: 'não se regozija com a injustiça, mas se regozija com a verdade;' },
      { v: 7, en: 'bears all things, believes all things, hopes all things, endures all things.', pt: 'tudo sofre, tudo crê, tudo espera, tudo suporta.' },
      { v: 8, en: 'Love never fails. But where there are prophecies, they will be done away with. Where there are various languages, they will cease. Where there is knowledge, it will be done away with.', pt: 'O amor jamais acaba; mas havendo profecias, serão aniquiladas; havendo línguas, cessarão; havendo ciência, desaparecerá;' },
      { v: 9, en: 'For we know in part, and we prophesy in part;', pt: 'porque, em parte conhecemos, e em parte profetizamos;' },
      { v: 10, en: 'but when that which is complete has come, then that which is partial will be done away with.', pt: 'mas, quando vier o que é perfeito, então o que é em parte será aniquilado.' },
      { v: 11, en: 'When I was a child, I spoke as a child, I felt as a child, I thought as a child. Now that I have become a man, I have put away childish things.', pt: 'Quando eu era menino, pensava como menino; mas, logo que cheguei a ser homem, acabei com as coisas de menino.' },
      { v: 12, en: 'For now we see in a mirror, dimly, but then face to face. Now I know in part, but then I will know fully, even as I was also fully known.', pt: 'Porque agora vemos como por espelho, em enigma, mas então veremos face a face; agora conheço em parte, mas então conhecerei plenamente, como também sou plenamente conhecido.' },
      { v: 13, en: 'But now faith, hope, and love remain—these three. The greatest of these is love.', pt: 'Agora, pois, permanecem a fé, a esperança, o amor, estes três; mas o maior destes é o amor.' },
    ],
    14: [
      { v: 1, en: 'Follow after love, and earnestly desire spiritual gifts, but especially that you may prophesy.', pt: 'Segui o amor; e procurai com zelo os dons espirituais, mas principalmente o de profetizar.' },
      { v: 2, en: 'For he who speaks in another language speaks not to men, but to God; for no one understands; but in the Spirit he speaks mysteries.', pt: 'Porque o que fala em língua não fala aos homens, mas a Deus; pois ninguém o entende; porque em espírito fala mistérios.' },
      { v: 3, en: 'But he who prophesies speaks to men for their edification, exhortation, and consolation.', pt: 'Mas o que profetiza fala aos homens para edificação, exortação e consolação.' },
      { v: 4, en: 'He who speaks in another language edifies himself, but he who prophesies edifies the assembly.', pt: 'O que fala em língua edifica-se a si mesmo, mas o que profetiza edifica a igreja.' },
      { v: 5, en: 'Now I desire to have you all speak with other languages, but rather that you would prophesy. For he is greater who prophesies than he who speaks with other languages, unless he interprets, that the assembly may be built up.', pt: 'Ora, quero que todos vós faleis em línguas, mas muito mais que profetizeis, pois quem profetiza é maior do que aquele que fala em línguas, a não ser que também intercede para que a igreja receba edificação.' },
      { v: 6, en: 'But now, brothers, if I come to you speaking with other languages, what would I profit you, unless I speak to you either by way of revelation, or of knowledge, or of prophesying, or of teaching?', pt: 'E agora, irmãos, se eu for ter convosco falando em línguas, de que vos aproveitarei, se vos não falar ou por meio de revelação, ou de ciência, ou de profecia, ou de doutrina?' },
      { v: 7, en: 'Even things without life, giving a voice, whether pipe or harp, if they didn’t give a distinction in the sounds, how would it be known what is piped or harped?', pt: 'Ora, até as coisas inanimadas, que emitem som, seja flauta, seja cítara, se não formarem sons distintos, como se conhecerá o que se toca na flauta ou na cítara?' },
      { v: 8, en: 'For if the trumpet gave an uncertain sound, who would prepare himself for war?', pt: 'Porque, se a trombeta der sonido incerto, quem se preparará para a batalha?' },
      { v: 9, en: 'So also you, unless you uttered by the tongue words easy to understand, how would it be known what is spoken? For you would be speaking into the air.', pt: 'Assim também vós, se com a língua não pronunciardes palavras bem inteligíveis, como se entenderá o que se diz? porque estareis como que falando ao ar.' },
      { v: 10, en: 'There are, it may be, so many kinds of sounds in the world, and none of them is without meaning.', pt: 'Há, por exemplo, tantas espécies de vozes no mundo, e nenhuma delas sem significação.' },
      { v: 11, en: 'If then I don’t know the meaning of the sound, I would be to him who speaks a foreigner, and he who speaks would be a foreigner to me.', pt: 'Se, pois, eu não souber o sentido da voz, serei estrangeiro para aquele que fala, e o que fala será estrangeiro para mim.' },
      { v: 12, en: 'So also you, since you are zealous for spiritual gifts, seek that you may abound to the building up of the assembly.', pt: 'Assim também vós, já que estais desejosos de dons espirituais, procurai abundar neles para a edificação da igreja.' },
      { v: 13, en: 'Therefore let him who speaks in another language pray that he may interpret.', pt: 'Por isso, o que fala em língua, ore para que a possa interpretar.' },
      { v: 14, en: 'For if I pray in another language, my spirit prays, but my understanding is unfruitful.', pt: 'Porque se eu orar em língua, o meu espírito ora, sim, mas o meu entendimento fica infrutífero.' },
      { v: 15, en: 'What is it then? I will pray with the spirit, and I will pray with the understanding also. I will sing with the spirit, and I will sing with the understanding also.', pt: 'Que fazer, pois? Orarei com o espírito, mas também orarei com o entendimento; cantarei com o espírito, mas também cantarei com o entendimento.' },
      { v: 16, en: 'Otherwise if you bless with the spirit, how will he who fills the place of the unlearned say the “Amen” at your giving of thanks, seeing he doesn’t know what you say?', pt: 'De outra maneira, se tu bendisseres com o espírito, como dirá o amém sobre a tua ação de graças aquele que ocupa o lugar de indouto, visto que não sabe o que dizes?' },
      { v: 17, en: 'For you most certainly give thanks well, but the other person is not built up.', pt: 'Porque realmente tu dás bem as graças, mas o outro não é edificado.' },
      { v: 18, en: 'I thank my God, I speak with other languages more than you all.', pt: 'Dou graças a Deus, que falo em línguas mais do que vós todos.' },
      { v: 19, en: 'However in the assembly I would rather speak five words with my understanding, that I might instruct others also, than ten thousand words in another language.', pt: 'Todavia na igreja eu antes quero falar cinco palavras com o meu entendimento, para que possa também instruir os outros, do que dez mil palavras em língua.' },
      { v: 20, en: 'Brothers, don’t be children in thoughts, yet in malice be babies, but in thoughts be mature.', pt: 'Irmãos, não sejais meninos no entendimento; na malícia, contudo, sede criancinhas, mas adultos no entendimento.' },
      { v: 21, en: 'In the law it is written, “By men of strange languages and by the lips of strangers I will speak to this people. Not even thus will they hear me, says the Lord.”', pt: 'Está escrito na lei: Por homens de outras línguas e por lábios de estrangeiros falarei a este povo; e nem assim me ouvirão, diz o Senhor.' },
      { v: 22, en: 'Therefore other languages are for a sign, not to those who believe, but to the unbelieving; but prophesying is for a sign, not to the unbelieving, but to those who believe.', pt: 'De modo que as línguas são um sinal, não para os crentes, mas para os incrédulos; a profecia, porém, não é sinal para os incrédulos, mas para os crentes.' },
      { v: 23, en: 'If therefore the whole assembly is assembled together and all speak with other languages, and unlearned or unbelieving people come in, won’t they say that you are crazy?', pt: 'Se, pois, toda a igreja se reunir num mesmo lugar, e todos falarem em línguas, e entrarem indoutos ou incrédulos, não dirão porventura que estais loucos?' },
      { v: 24, en: 'But if all prophesy, and someone unbelieving or unlearned comes in, he is reproved by all, and he is judged by all.', pt: 'Mas, se todos profetizarem, e algum incrédulo ou indouto entrar, por todos é convencido, por todos é julgado;' },
      { v: 25, en: 'And thus the secrets of his heart are revealed. So he will fall down on his face and worship God, declaring that God is among you indeed.', pt: 'os segredos do seu coração se tornam manifestos; e assim, prostrando-se sobre o seu rosto, adorará a Deus, declarando que Deus está verdadeiramente entre vós.' },
      { v: 26, en: 'What is it then, brothers? When you come together, each one of you has a psalm, has a teaching, has a revelation, has another language, has an interpretation. Let all things be done to build each other up.', pt: 'Que fazer, pois, irmãos? Quando vos congregais, cada um de vós tem salmo, tem doutrina, tem revelação, tem língua, tem interpretação. Faça-se tudo para edificação.' },
      { v: 27, en: 'If any man speaks in another language, let it be two, or at the most three, and in turn; and let one interpret.', pt: 'Se alguém falar em língua, faça-se isso por dois, ou quando muito três, e cada um por sua vez, e haja um que interprete.' },
      { v: 28, en: 'But if there is no interpreter, let him keep silent in the assembly, and let him speak to himself, and to God.', pt: 'Mas, se não houver intérprete, esteja calado na igreja, e fale consigo mesmo, e com Deus.' },
      { v: 29, en: 'Let the prophets speak, two or three, and let the others discern.', pt: 'E falem os profetas, dois ou três, e os outros julguem.' },
      { v: 30, en: 'But if a revelation is made to another sitting by, let the first keep silent.', pt: 'Mas se a outro, que estiver sentado, for revelada alguma coisa, cale-se o primeiro.' },
      { v: 31, en: 'For you all can prophesy one by one, that all may learn, and all may be exhorted.', pt: 'Porque todos podereis profetizar, cada um por sua vez; para que todos aprendam e todos sejam cosolados;' },
      { v: 32, en: 'The spirits of the prophets are subject to the prophets,', pt: 'pois os espíritos dos profetas estão sujeitos aos profetas;' },
      { v: 33, en: 'for God is not a God of confusion, but of peace, as in all the assemblies of the saints.', pt: 'porque Deus não é Deus de confusão, mas sim de paz. Como em todas as igrejas dos santos,' },
      { v: 34, en: 'Let the wives be quiet in the assemblies, for it has not been permitted for them to be talking except in submission, as the law also says,', pt: 'as mulheres estejam caladas nas igrejas; porque lhes não é permitido falar; mas estejam submissas como também ordena a lei.' },
      { v: 35, en: 'if they desire to learn anything. “Let them ask their own husbands at home, for it is shameful for a wife to be talking in the assembly.”', pt: 'E, se querem aprender alguma coisa, perguntem em casa a seus próprios maridos; porque é indecoroso para a mulher o falar na igreja.' },
      { v: 36, en: 'What!? Was it from you that the word of God went out? Or did it come to you alone?', pt: 'Porventura foi de vós que partiu a palavra de Deus? Ou veio ela somente para vós?' },
      { v: 37, en: 'If any man thinks himself to be a prophet, or spiritual, let him recognize the things which I write to you, that they are the commandment of the Lord.', pt: 'Se alguém se considera profeta, ou espiritual, reconheça que as coisas que vos escrevo são mandamentos do Senhor.' },
      { v: 38, en: 'But if anyone is ignorant, let him be ignorant.', pt: 'Mas, se alguém ignora isto, ele é ignorado.' },
      { v: 39, en: 'Therefore, brothers, desire earnestly to prophesy, and don’t forbid speaking with other languages.', pt: 'Portanto, irmãos, procurai com zelo o profetizar, e não proibais o falar em línguas.' },
      { v: 40, en: 'Let all things be done decently and in order.', pt: 'Mas faça-se tudo decentemente e com ordem.' },
    ],
    15: [
      { v: 1, en: 'Now I declare to you, brothers, the Good News which I preached to you, which also you received, in which you also stand,', pt: 'Ora, eu vos lembro, irmãos, o evangelho que já vos anunciei; o qual também recebestes, e no qual perseverais,' },
      { v: 2, en: 'by which also you are saved, if you hold firmly the word which I preached to you—unless you believed in vain.', pt: 'pelo qual também sois salvos, se é que o conservais tal como vo-lo anunciei; se não é que crestes em vão.' },
      { v: 3, en: 'For I delivered to you first of all that which I also received: that Christ died for our sins according to the Scriptures,', pt: 'Porque primeiramente vos entreguei o que também recebi: que Cristo morreu por nossos pecados, segundo as Escrituras;' },
      { v: 4, en: 'that he was buried, that he was raised on the third day according to the Scriptures,', pt: 'que foi sepultado; que foi ressuscitado ao terceiro dia, segundo as Escrituras;' },
      { v: 5, en: 'and that he appeared to Cephas, then to the twelve.', pt: 'que apareceu a Cefas, e depois aos doze;' },
      { v: 6, en: 'Then he appeared to over five hundred brothers at once, most of whom remain until now, but some have also fallen asleep.', pt: 'depois apareceu a mais de quinhentos irmãos duma vez, dos quais vive ainda a maior parte, mas alguns já dormiram;' },
      { v: 7, en: 'Then he appeared to James, then to all the apostles,', pt: 'depois apareceu a Tiago, então a todos os apóstolos;' },
      { v: 8, en: 'and last of all, as to the child born at the wrong time, he appeared to me also.', pt: 'e por derradeiro de todos apareceu também a mim, como a um abortivo.' },
      { v: 9, en: 'For I am the least of the apostles, who is not worthy to be called an apostle, because I persecuted the assembly of God.', pt: 'Pois eu sou o menor dos apóstolos, que nem sou digno de ser chamado apóstolo, porque persegui a igreja de Deus.' },
      { v: 10, en: 'But by the grace of God I am what I am. His grace which was given to me was not futile, but I worked more than all of them; yet not I, but the grace of God which was with me.', pt: 'Mas pela graça de Deus sou o que sou; e a sua graça para comigo não foi vã, antes trabalhei muito mais do que todos eles; todavia não eu, mas a graça de Deus que está comigo.' },
      { v: 11, en: 'Whether then it is I or they, so we preach, and so you believed.', pt: 'Então, ou seja eu ou sejam eles, assim pregamos e assim crestes.' },
      { v: 12, en: 'Now if Christ is preached, that he has been raised from the dead, how do some among you say that there is no resurrection of the dead?', pt: 'Ora, se se prega que Cristo foi ressucitado dentre os mortos, como dizem alguns entre vós que não há ressurreição de mortos?' },
      { v: 13, en: 'But if there is no resurrection of the dead, neither has Christ been raised.', pt: 'Mas se não há ressurreição de mortos, também Cristo não foi ressuscitado.' },
      { v: 14, en: 'If Christ has not been raised, then our preaching is in vain, and your faith also is in vain.', pt: 'E, se Cristo não foi ressuscitado, logo é vã a nossa pregação, e também é vã a vossa fé.' },
      { v: 15, en: 'Yes, we are also found false witnesses of God, because we testified about God that he raised up Christ, whom he didn’t raise up, if it is so that the dead are not raised.', pt: 'E assim somos também considerados como falsas testemunhas de Deus que ele ressuscitou a Cristo, ao qual, porém, não ressuscitou, se, na verdade, os mortos não são ressuscitados.' },
      { v: 16, en: 'For if the dead aren’t raised, neither has Christ been raised.', pt: 'Porque, se os mortos não são ressuscitados, também Cristo não foi ressuscitado.' },
      { v: 17, en: 'If Christ has not been raised, your faith is vain; you are still in your sins.', pt: 'E, se Cristo não foi ressuscitado, é vã a vossa fé, e ainda estais nos vossos pecados.' },
      { v: 18, en: 'Then they also who are fallen asleep in Christ have perished.', pt: 'Logo, também os que dormiram em Cristo estão perdidos.' },
      { v: 19, en: 'If we have only hoped in Christ in this life, we are of all men most pitiable.', pt: 'Se é só para esta vida que esperamos em Cristo, somos de todos os homens os mais dignos de lástima.' },
      { v: 20, en: 'But now Christ has been raised from the dead. He became the first fruits of those who are asleep.', pt: 'Mas na realidade Cristo foi ressuscitado dentre os mortos, sendo ele as primícias dos que dormem.' },
      { v: 21, en: 'For since death came by man, the resurrection of the dead also came by man.', pt: 'Porque, assim como por um homem veio a morte, também por um homem veio a ressurreição dos mortos.' },
      { v: 22, en: 'For as in Adam all die, so also in Christ all will be made alive.', pt: 'Pois como em Adão todos morrem, do mesmo modo em Cristo todos serão vivificados.' },
      { v: 23, en: 'But each in his own order: Christ the first fruits, then those who are Christ’s, at his coming.', pt: 'Cada um, porém, na sua ordem: Cristo as primícias, depois os que são de Cristo, na sua vinda.' },
      { v: 24, en: 'Then the end comes, when he will deliver up the Kingdom to God, even the Father; when he will have abolished all rule and all authority and power.', pt: 'Então virá o fim quando ele entregar o reino a Deus o Pai, quando houver destruído todo domínio, e toda autoridade e todo poder.' },
      { v: 25, en: 'For he must reign until he has put all his enemies under his feet.', pt: 'Pois é necessário que ele reine até que haja posto todos os inimigos debaixo de seus pés.' },
      { v: 26, en: 'The last enemy that will be abolished is death.', pt: 'Ora, o último inimigo a ser destruído é a morte.' },
      { v: 27, en: 'For, “He put all things in subjection under his feet.” But when he says, “All things are put in subjection”, it is evident that he is excepted who subjected all things to him.', pt: 'Pois se lê: Todas as coisas sujeitou debaixo de seus pés. Mas, quando diz: Todas as coisas lhe estão sujeitas, claro está que se excetua aquele que lhe sujeitou todas as coisas.' },
      { v: 28, en: 'When all things have been subjected to him, then the Son will also himself be subjected to him who subjected all things to him, that God may be all in all.', pt: 'E, quando todas as coisas lhe estiverem sujeitas, então também o próprio Filho se sujeitará àquele que todas as coisas lhe sujeitou, para que Deus seja tudo em todos.' },
      { v: 29, en: 'Or else what will they do who are baptized for the dead? If the dead aren’t raised at all, why then are they baptized for the dead?', pt: 'De outra maneira, que farão os que se batizam pelos mortos? Se absolutamente os mortos não ressuscitam, por que então se batizam por eles?' },
      { v: 30, en: 'Why do we also stand in jeopardy every hour?', pt: 'E por que nos expomos também nós a perigos a toda hora?' },
      { v: 31, en: 'I affirm, by the boasting in you which I have in Christ Jesus our Lord, I die daily.', pt: 'Eu vos declaro, irmãos, pela glória que de vós tenho em Cristo Jesus nosso Senhor, que morro todos os dias.' },
      { v: 32, en: 'If I fought with animals at Ephesus for human purposes, what does it profit me? If the dead are not raised, then “let us eat and drink, for tomorrow we die.”', pt: 'Se, como homem, combati em Éfeso com as feras, que me aproveita isso? Se os mortos não são ressuscitados, comamos e bebamos, porque amanhã morreremos.' },
      { v: 33, en: 'Don’t be deceived! “Evil companionships corrupt good morals.”', pt: 'Não vos enganeis. As más companhias corrompem os bons costumes.' },
      { v: 34, en: 'Wake up righteously, and don’t sin, for some have no knowledge of God. I say this to your shame.', pt: 'Acordai para a justiça e não pequeis mais; porque alguns ainda não têm conhecimento de Deus; digo-o para vergonha vossa.' },
      { v: 35, en: 'But someone will say, “How are the dead raised?” and, “With what kind of body do they come?”', pt: 'Mas alguém dirá: Como ressuscitam os mortos? e com que qualidade de corpo vêm?' },
      { v: 36, en: 'You foolish one, that which you yourself sow is not made alive unless it dies.', pt: 'Insensato! o que tu semeias não é vivificado, se primeiro não morrer.' },
      { v: 37, en: 'That which you sow, you don’t sow the body that will be, but a bare grain, maybe of wheat, or of some other kind.', pt: 'E, quando semeias, não semeias o corpo que há de nascer, mas o simples grão, como o de trigo, ou o de outra qualquer semente.' },
      { v: 38, en: 'But God gives it a body even as it pleased him, and to each seed a body of its own.', pt: 'Mas Deus lhe dá um corpo como lhe aprouve, e a cada uma das sementes um corpo próprio.' },
      { v: 39, en: 'All flesh is not the same flesh, but there is one flesh of men, another flesh of animals, another of fish, and another of birds.', pt: 'Nem toda carne é uma mesma carne; mas uma é a carne dos homens, outra a carne dos animais, outra a das aves e outra a dos peixes.' },
      { v: 40, en: 'There are also celestial bodies, and terrestrial bodies; but the glory of the celestial differs from that of the terrestrial.', pt: 'Também há corpos celestes e corpos terrestres, mas uma é a glória dos celestes e outra a dos terrestres.' },
      { v: 41, en: 'There is one glory of the sun, another glory of the moon, and another glory of the stars; for one star differs from another star in glory.', pt: 'Uma é a glória do sol, outra a glória da lua e outra a glória das estrelas; porque uma estrela difere em glória de outra estrela.' },
      { v: 42, en: 'So also is the resurrection of the dead. The body is sown perishable; it is raised imperishable.', pt: 'Assim também é a ressurreição, é ressuscitado em incorrupção.' },
      { v: 43, en: 'It is sown in dishonor; it is raised in glory. It is sown in weakness; it is raised in power.', pt: 'Semeia-se em ignomínia, é ressuscitado em glória. Semeia-se em fraqueza, é ressuscitado em poder.' },
      { v: 44, en: 'It is sown a natural body; it is raised a spiritual body. There is a natural body and there is also a spiritual body.', pt: 'Semeia-se corpo animal, é ressuscitado corpo espiritual. Se há corpo animal, há também corpo espiritual.' },
      { v: 45, en: 'So also it is written, “The first man, Adam, became a living soul.” The last Adam became a life-giving spirit.', pt: 'Assim também está escrito: O primeiro homem, Adão, tornou-se alma vivente; o último Adão, espírito vivificante.' },
      { v: 46, en: 'However that which is spiritual isn’t first, but that which is natural, then that which is spiritual.', pt: 'Mas não é primeiro o espíritual, senão o animal; depois o espiritual.' },
      { v: 47, en: 'The first man is of the earth, made of dust. The second man is the Lord from heaven.', pt: 'O primeiro homem, sendo da terra, é terreno; o segundo homem é do céu.' },
      { v: 48, en: 'As is the one made of dust, such are those who are also made of dust; and as is the heavenly, such are they also that are heavenly.', pt: 'Qual o terreno, tais também os terrenos; e, qual o celestial, tais também os celestiais.' },
      { v: 49, en: 'As we have borne the image of those made of dust, let’s also bear the image of the heavenly.', pt: 'E, assim como trouxemos a imagem do terreno, traremos também a imagem do celestial.' },
      { v: 50, en: 'Now I say this, brothers, that flesh and blood can’t inherit God’s Kingdom; neither does the perishable inherit imperishable.', pt: 'Mas digo isto, irmãos, que carne e sangue não podem herdar o reino de Deus; nem a corrupção herda a incorrupção.' },
      { v: 51, en: 'Behold, I tell you a mystery. We will not all sleep, but we will all be changed,', pt: 'Eis aqui vos digo um mistério: Nem todos dormiremos mas todos seremos transformados,' },
      { v: 52, en: 'in a moment, in the twinkling of an eye, at the last trumpet. For the trumpet will sound, and the dead will be raised incorruptible, and we will be changed.', pt: 'num momento, num abrir e fechar de olhos, ao som da última trombeta; porque a trombeta soará, e os mortos serão ressuscitados incorruptíveis, e nós seremos transformados.' },
      { v: 53, en: 'For this perishable body must become imperishable, and this mortal must put on immortality.', pt: 'Porque é necessário que isto que é corruptível se revista da incorruptibilidade e que isto que é mortal se revista da imortalidade.' },
      { v: 54, en: 'But when this perishable body will have become imperishable, and this mortal will have put on immortality, then what is written will happen: “Death is swallowed up in victory.”', pt: 'Mas, quando isto que é corruptível se revestir da incorruptibilidade, e isto que é mortal se revestir da imortalidade, então se cumprirá a palavra que está escrito: Tragada foi a morte na vitória.' },
      { v: 55, en: '“Death, where is your sting? Hades, where is your victory?”', pt: 'Onde está, ó morte, a tua vitória? Onde está, ó morte, o teu aguilhão?' },
      { v: 56, en: 'The sting of death is sin, and the power of sin is the law.', pt: 'O aguilhão da morte é o pecado, e a força do pecado é a lei.' },
      { v: 57, en: 'But thanks be to God, who gives us the victory through our Lord Jesus Christ.', pt: 'Mas graça a Deus que nos dá a vitória por nosso Senhor Jesus Cristo.' },
      { v: 58, en: 'Therefore, my beloved brothers, be steadfast, immovable, always abounding in the Lord’s work, because you know that your labor is not in vain in the Lord.', pt: 'Portanto, meus amados irmãos, sede firmes e constantes, sempre abundantes na obra do Senhor, sabendo que o vosso trabalho não é vão no Senhor.' },
    ],
    16: [
      { v: 1, en: 'Now concerning the collection for the saints, as I commanded the assemblies of Galatia, you do likewise.', pt: 'Ora, quanto à coleta para os santos fazei vós também o mesmo que ordenei às igrejas da Galiléia.' },
      { v: 2, en: 'On the first day of the week, let each one of you save, as he may prosper, that no collections be made when I come.', pt: 'No primeiro dia da semana cada um de vós ponha de parte o que puder, conforme tiver prosperado, guardando-o, para que se não façam coletas quando eu chegar.' },
      { v: 3, en: 'When I arrive, I will send whoever you approve with letters to carry your gracious gift to Jerusalem.', pt: 'E, quando tiver chegado, mandarei os que por carta aprovardes para levar a vossa dádiva a Jerusalém;' },
      { v: 4, en: 'If it is appropriate for me to go also, they will go with me.', pt: 'mas, se valer a pena que eu também vá, irão comigo.' },
      { v: 5, en: 'But I will come to you when I have passed through Macedonia, for I am passing through Macedonia.', pt: 'Irei, porém, ter convosco depois de ter passado pela Macedônia, pois tenho de passar pela Macedônia;' },
      { v: 6, en: 'But with you it may be that I will stay, or even winter, that you may send me on my journey wherever I go.', pt: 'e talvez demore convosco algum tempo, ou mesmo passe o inverno, para que me encaminheis para onde quer que eu for.' },
      { v: 7, en: 'For I do not wish to see you now in passing, but I hope to stay a while with you, if the Lord permits.', pt: 'Pois não quero ver-vos desta vez apenas de passagem, antes espero ficar convosco algum tempo, se o Senhor o permitir.' },
      { v: 8, en: 'But I will stay at Ephesus until Pentecost,', pt: 'Ficarei, porém, em Éfeso até o Pentecostes;' },
      { v: 9, en: 'for a great and effective door has opened to me, and there are many adversaries.', pt: 'porque uma porta grande e eficaz se me abriu; e há muitos adversários.' },
      { v: 10, en: 'Now if Timothy comes, see that he is with you without fear, for he does the work of the Lord, as I also do.', pt: 'Ora, se Timóteo for, vede que esteja sem temor entre vós; porque trabalha na obra do Senhor, como eu também,' },
      { v: 11, en: 'Therefore let no one despise him. But set him forward on his journey in peace, that he may come to me; for I expect him with the brothers.', pt: 'Portanto ninguém o despreze; mas encaminhai-o em paz, para que venha ter comigo, pois o espero com os irmãos.' },
      { v: 12, en: 'Now concerning Apollos, the brother, I strongly urged him to come to you with the brothers; and it was not at all his desire to come now; but he will come when he has an opportunity.', pt: 'Quanto ao irmão Apolo, roguei-lhe muito que fosse com os irmãos ter convosco; mas de modo algum quis ir agora; irá porém, quando se lhe ofereça boa ocasião.' },
      { v: 13, en: 'Watch! Stand firm in the faith! Be courageous! Be strong!', pt: 'Vigiai, estai firmes na fé, portai-vos varonilmente, sede fortes.' },
      { v: 14, en: 'Let all that you do be done in love.', pt: 'Todas as vossas obras sejam feitas em amor.' },
      { v: 15, en: 'Now I beg you, brothers (you know the house of Stephanas, that it is the first fruits of Achaia, and that they have set themselves to serve the saints),', pt: 'Agora vos rogo, irmãos - pois sabeis que a família de Estéfanas é as primícias da Acaía, e que se tem dedicado ao ministério dos santos -' },
      { v: 16, en: 'that you also be in subjection to such, and to everyone who helps in the work and labors.', pt: 'que também vos sujeiteis aos tais, e a todo aquele que auxilia na obra e trabalha.' },
      { v: 17, en: 'I rejoice at the coming of Stephanas, Fortunatus, and Achaicus; for that which was lacking on your part, they supplied.', pt: 'Regozijo-me com a vinda de Estéfanas, de Fortunato e de Acaico; porque estes supriram o que da vossa parte me faltava.' },
      { v: 18, en: 'For they refreshed my spirit and yours. Therefore acknowledge those who are like that.', pt: 'Porque recrearam o meu espírito assim como o vosso. Reconhecei, pois, aos tais.' },
      { v: 19, en: 'The assemblies of Asia greet you. Aquila and Priscilla greet you much in the Lord, together with the assembly that is in their house.', pt: 'As igrejas da Ásia vos saúdam. Saúdam-vos afetuosamente no Senhor Aqüila e Priscila, com a igreja que está em sua casa.' },
      { v: 20, en: 'All the brothers greet you. Greet one another with a holy kiss.', pt: 'Todos os irmãos vos saúdam. Saudai-vos uns aos outros com ósculo santo.' },
      { v: 21, en: 'This greeting is by me, Paul, with my own hand.', pt: 'Esta saudação é de meu próprio punho, Paulo.' },
      { v: 22, en: 'If any man doesn’t love the Lord Jesus Christ, let him be accursed. Come, Lord!', pt: 'Se alguém não ama ao Senhor, seja anátema! Maranata.' },
      { v: 23, en: 'The grace of the Lord Jesus Christ be with you.', pt: 'A graça do Senhor Jesus seja convosco.' },
      { v: 24, en: 'My love to all of you in Christ Jesus. Amen.', pt: 'O meu amor seja com todos vós em Cristo Jesus.' },
    ],
  },
};

export default book;
